suggestions=document.getElementById("suggestions"),search=document.getElementById("search"),search!==null&&document.addEventListener("keydown",inputFocus);function inputFocus(e){e.ctrlKey&&e.key==="/"&&(e.preventDefault(),search.focus()),e.key==="Escape"&&(search.blur(),suggestions.classList.add("d-none"))}document.addEventListener("click",function(e){var t=suggestions.contains(e.target);t||suggestions.classList.add("d-none")}),document.addEventListener("keydown",suggestionFocus);function suggestionFocus(e){const s=suggestions.classList.contains("d-none");if(s)return;const t=[...suggestions.querySelectorAll("a")];if(t.length===0)return;const n=t.indexOf(document.activeElement);if(e.key==="ArrowUp"){e.preventDefault();const s=n>0?n-1:0;t[s].focus()}else if(e.key==="ArrowDown"){e.preventDefault();const s=n+1<t.length?n+1:n;t[s].focus()}}(function(){var e=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:"id",store:["href","title","description"],index:["title","description","content"]}});e.add({id:0,href:"/posts/n8n-moneyprinter-short/",title:"Автоматизация Shorts: n8n, MoneyPrinterTurbo, Postiz, Baserow",description:"Полный пайплайн автоматической генерации и публикации коротких видео на 5 соцсетей с помощью n8n, AI и открытых инструментов.",content:`Одна кнопка — и короткое видео автоматически генерируется AI, загружается и публикуется на TikTok, YouTube Shorts, Instagram, Facebook и Threads. В этом посте покажу полный пайплайн, собранный на четырёх открытых инструментах.
Зачем автоматизировать Shorts # Короткие видео — это основной формат для роста аудитории в 2025 году. Но ручное создание контента требует много времени: написание сценариев, монтаж, публикация на каждой платформе отдельно.
Автоматизация решает эту проблему. Один workflow в n8n выполняет весь цикл:
Генерирует тему и сценарий с помощью AI Создаёт видео с озвучкой и субтитрами Загружает на 5 соцсетей одновременно Уведомляет в Telegram о результатах Весь процесс работает без участия человека.
Инструменты # n8n — оркестратор # n8n — платформа для автоматизации workflows с визуальным конструктором. Поддерживает 400+ интеграций, нативные AI-возможности (LangChain, Gemini, OpenAI) и написание кода на JavaScript/Python.
Ключевые преимущества для нашего пайплайна:
Визуальная связка узлов — понятно, что и куда передаёт данные Встроенные HTTP-запросы для работы с API Планировщик задач (cron) для автоматического запуска Self-hosted — все данные на вашем сервере MoneyPrinterTurbo — AI-генерация видео # MoneyPrinterTurbo — открытый инструмент для генерации коротких видео. Даёшь тему или ключевое слово — получаешь готовое видео с озвучкой, субтитрами и фоновой музыкой.
Возможности:
AI-генерация сценариев (OpenAI, Gemini, DeepSeek, Ollama) Синтез речи (Edge TTS, Azure, SiliconFlow) Автоматические субтитры с настройкой стиля Библиотека бесплатных видео (Pexels, Pixabay) Фоновая музыка с регулировкой громкости Batch-генерация — несколько вариантов за раз REST API для интеграции с внешними системами Деплой через Docker:
git clone https://github.com/harry0703/MoneyPrinterTurbo\rcd MoneyPrinterTurbo\rdocker compose up -d\rWeb-интерфейс доступен на http://localhost:8080, API — на http://localhost:8080/api/v1.
Baserow — база данных # Baserow — open-source альтернатива Airtable. Self-hosted, с REST API и вебхуками. Используется для хранения всех данных пайплайна: тем, сценариев, URL видео, статусов публикации.
Поля таблицы:
topic — тема видео script_text — сгенерированный сценарий video_prompt — промпт для MoneyPrinterTurbo search_tags — теги для поиска видео shorts_tags — хэштеги для постов task_id — ID задачи в MoneyPrinterTurbo video_url — путь к готовому видео postiz_id / postiz_path — ID и путь в Postiz status — статус (approved → processing → done → publish) publish_links — ссылки на опубликованные посты Postiz — менеджер соцсетей # Postiz — открытый инструмент для планирования и публикации контента на 30+ платформах. Self-hosted, с API для интеграции.
Поддерживаемые платформы для Shorts:
TikTok YouTube Shorts Instagram Reels Facebook Reels Threads Архитектура пайплайна # Workflow в n8n выполняет следующую последовательность:
┌─────────────────────────────────────────────────────────────┐\r│ 1. Триггер (cron каждые N часов или ручной запуск) │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 2. Генерация темы (JavaScript) │\r│ - Случайная тема из предопределённого списка │\r│ - Стиль хука, CTA, теги │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 3. AI генерация сценария (Google Gemini) │\r│ - title, fomo_text, video_prompt, shorts_tags │\r│ - JSON-формат для парсинга │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 4. Сохранение в Baserow (status: approved) │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 5. Создание видео (MoneyPrinterTurbo API) │\r│ - POST /api/v1/videos с промптом и настройками │\r│ - aspect: 9:16, голос: Fenrir-Male, субтитры: вкл │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 6. Ожидание готовности (polling каждые 2 минуты) │\r│ - GET /api/v1/tasks/{task_id} │\r│ - Проверка progress === 100 │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 7. Загрузка видео в Postiz │\r│ - uploadFile с binary data │\r│ - Сохранение postiz_id и postiz_path в Baserow │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 8. Публикация на 5 платформ │\r│ - Фильтрация по identifier: tiktok, youtube, facebook, │\r│ instagram, threads │\r│ - Schedule on [Platform] с настройками │\r└──────────────────────────┬──────────────────────────────────┘\r↓\r┌─────────────────────────────────────────────────────────────┐\r│ 9. Уведомление в Telegram │\r│ - Список опубликованных ссылок │\r│ - Статус: published │\r└─────────────────────────────────────────────────────────────┘\rПошаговая настройка # 1. Docker Compose # Создайте docker-compose.yml со всеми сервисами:
services:\rn8n:\rimage: n8nio/n8n:latest\rrestart: unless-stopped\rports:\r- &quot;5678:5678&quot;\rvolumes:\r- n8n_data:/home/node/.n8n\renvironment:\r- N8N_BASIC_AUTH_ACTIVE=true\r- N8N_BASIC_AUTH_USER=admin\r- N8N_BASIC_AUTH_PASSWORD=your_password\r- GENERIC_TIMEZONE=Europe/Moscow\r- TZ=Europe/Moscow\rmoneyprinter:\rimage: harry0703/moneyprinterturbo:latest\rrestart: unless-stopped\rports:\r- &quot;8080:8080&quot;\rvolumes:\r- mp_config:/app/config\r- mp_videos:/app/output\rpostiz:\rimage: gitroomhq/postiz-app:latest\rrestart: unless-stopped\rports:\r- &quot;5000:5000&quot;\renvironment:\r- DATABASE_URL=postgres://postiz:postiz@postgres:5432/postiz\rdepends_on:\r- postgres\rpostgres:\rimage: postgres:15\rrestart: unless-stopped\renvironment:\r- POSTGRES_DB=postiz\r- POSTGRES_USER=postiz\r- POSTGRES_PASSWORD=postiz\rvolumes:\r- pg_data:/var/lib/postgresql/data\rvolumes:\rn8n_data:\rmp_config:\rmp_videos:\rbaserow_data:\rpg_data:\rЗапуск:
docker compose up -d\r2. Таблица в Baserow # Создайте базу данных и таблицу со следующими полями:
Поле Тип Описание topic Text Тема видео script_text Long text Сценарий для озвучки video_prompt Text Промпт для MoneyPrinterTurbo search_tags Text Теги через запятую shorts_tags Text Хэштеги через запятую task_id Text ID задачи в MoneyPrinterTurbo video_url Text Путь к видео postiz_id Text ID файла в Postiz postiz_path Text Путь к файлу в Postiz status Text Статус: approved/processing/done/publish publish_links Long text Ссылки на опубликованные посты created_at Created Дата создания 3. Импорт workflow в n8n # Откройте n8n на http://localhost:5678 Импортируйте JSON-файл workflow Настройте credentials: Baserow Token — токен API Baserow Postiz API — API-ключ Postiz Google Gemini API — ключ Google AI Telegram Bot — токен бота и chat_id 4. Настройка Postiz # Откройте Postiz на http://localhost:5000 Зарегистрируйтесь и создайте организацию Подключите аккаунты соцсетей: TikTok YouTube Instagram Facebook Threads Скопируйте API-ключ из настроек 5. Конфигурация workflow # В n8n настройте параметры:
Schedule Trigger:
Интервал: каждые 2-4 часа (или по необходимости) Code in JavaScript:
Редактируйте список тем под вашу нишу Настройте стили хуков и CTA Добавьте запрещённые клише HTTP Request (MoneyPrinterTurbo):
URL: http://moneyprinter:8080/api/v1/videos Настройте параметры видео: video_aspect: &quot;9:16&quot; для Shorts voice_name: выберите голос video_language: &quot;ru&quot; для русского video_source: &quot;pexels&quot; или &quot;pixabay&quot; Postiz nodes:
Убедитесь, что integration IDs правильные Настройте настройки публикации для каждой платформы Детали workflow # Генератор тем # JavaScript-узел выбирает случайную тему из предопределённого списка:
const topics = [\r&quot;5 инструментов для автоматизации бизнеса&quot;,\r&quot;Почему open-source побеждает&quot;,\r&quot;Автоматизация соцсетей: полный гайд&quot;\r// ... ваши темы\r];\rconst hook_styles = [&quot;жёсткий&quot;, &quot;провокационный&quot;, &quot;спокойно-давящий&quot;, &quot;агрессивный&quot;, &quot;мотивирующий&quot;, &quot;ироничный&quot;];\rconst pick = (arr) =&gt; arr[Math.floor(Math.random() * arr.length)];\rreturn [\r{\rjson: {\rtopic: pick(topics),\rhook_style: pick(hook_styles),\rsearch_tags: &quot;viral, trending, tech, automation&quot;\r}\r}\r];\rПромпт для Gemini # AI получает инструкцию генерировать JSON с полями:
title — цепляющий заголовок fomo_text — сценарий для озвучки (40-60 секунд) video_prompt — промпт на английском для MoneyPrinterTurbo shorts_tags — 5 тегов транслитом Правила генерации:
Связная речь, без рваных фраз Эффект FOMO — зритель должен чувствовать, что упускает деньги Живая разговорная речь Никаких запрещённых клише Настройки видео # MoneyPrinterTurbo создаёт видео с параметрами:
{\r&quot;video_aspect&quot;: &quot;9:16&quot;,\r&quot;video_concat_mode&quot;: &quot;random&quot;,\r&quot;video_clip_duration&quot;: 5,\r&quot;match_materials_to_script&quot;: true,\r&quot;video_count&quot;: 1,\r&quot;video_source&quot;: &quot;pexels&quot;,\r&quot;video_language&quot;: &quot;ru&quot;,\r&quot;voice_name&quot;: &quot;gemini:Fenrir-Male&quot;,\r&quot;voice_rate&quot;: 1.1,\r&quot;subtitle_enabled&quot;: true,\r&quot;subtitle_position&quot;: &quot;custom&quot;,\r&quot;custom_position&quot;: 85.0,\r&quot;font_size&quot;: 50\r}\rПубликация на платформы # Postiz получает видео и публикует на каждой платформе с уникальными настройками:
TikTok:
privacy_level: PUBLIC_TO_EVERYONE comment: true content_posting_method: UPLOAD YouTube:
type: public Теги добавляются в описание Instagram:
post_type: post или story Facebook:
post_type: post Threads:
Теги в описании Советы # Rate limits # При частом использовании API могут быть ограничения:
Gemini: 15 запросов в минуту (бесплатный тариф) MoneyPrinterTurbo: зависит от мощности сервера Postiz: зависит от API соцсетей Обработка ошибок # n8n имеет встроенную обработку ошибок:
retryOnFail: true — повторные попытки maxTries: 5 — максимальное количество попыток waitBetweenTries: 5000 — пауза между попытками Мониторинг # Отслеживайте прогресс через Baserow:
approved — сценарий сгенерирован processing — видео создаётся done — видео готово publish — опубликовано на всех платформах Оптимизация # Запускайте workflow в непиковые часы Ограничьте количество видео за раз Используйте batch-генерацию для выбора лучшего варианта Читайте также # Настройка сервера Ubuntu 24.04 с Docker — базовая настройка сервера Настройка медиа-сервера в Docker — автоматизация загрузки фильмов Настройка Nginx и Docker Portainer — reverse proxy и управление контейнерами Ссылки # n8n — платформа автоматизации MoneyPrinterTurbo — AI-генерация видео Baserow — open-source база данных Postiz — менеджер соцсетей Docker — контейнеризация `}),e.add({id:1,href:"/posts/ubuntu-docker/",title:"Настройка сервера Ubuntu 24.04 с Docker, Nginx, Dockge, uptime-kuma",description:"В этой статье описан процесс настройки сервера Ubuntu 24.04 с акцентом на безопасность, установку Docker",content:`В этой статье описан процесс настройки сервера Ubuntu 24.04 с акцентом на безопасность, установку Docker, Nginx и удобного инструмента управления контейнерами Dockge. Мы создадим пользователя, настроим SSH, установим необходимые сервисы и обеспечим базовую защиту сети.
Video: https://youtu.be/tXoCfyIWmwA
🔥 aeza бонус 15% к пополнению: https://aeza.net/ 🔥 Приватная Email рассылка: https://creio.kit.com/subscribe 1. Создание пользователя # Начнем с создания пользователя ubuntu и настройки его окружения:
groupadd ubuntu\ruseradd -m -g ubuntu -G &quot;adm,users,sudo,docker&quot; -s /bin/bash ubuntu\rpasswd ubuntu\rexit\rКоманда создает пользователя с домашней директорией, добавляет его в группы adm, users и sudo, задает оболочку Bash и позволяет установить пароль.
2. Настройка SSH-доступа # Для безопасного подключения создадим SSH-ключ и передадим его на сервер:
ssh-keygen -t rsa -q -N '' -f ~/.ssh/id_rsa\rcat .ssh/id_rsa.pub | ssh root@45.223.22.224 'mkdir -p /home/ubuntu/.ssh &amp;&amp; cat &gt;&gt; /home/ubuntu/.ssh/authorized_keys'\rssh ubuntu@45.223.22.224\rГенерируется RSA-ключ без пароля, публичный ключ копируется в файл authorized_keys на сервере, затем выполняется подключение.
3. Конфигурация SSH-сервера # Настроим SSH для повышения безопасности:
sudo nano /etc/ssh/sshd_config\rУкажем следующие параметры:
Port 2222\rPermitRootLogin no\rPubkeyAuthentication yes\rAllowUsers ubuntu\rAuthorizedKeysFile .ssh/authorized_keys .ssh/authorized_keys2\rPasswordAuthentication no\rДополнительно отключим аутентификацию по паролю:
sudo nano /etc/ssh/sshd_config.d/50-cloud-init.conf\rPasswordAuthentication no\rПерезагрузим сервер:
reboot\r# или sshd\rsystemctl restart ssh\rПосле перезагрузки подключимся по новому порту:
ssh -p 2222 ubuntu@45.223.22.224\r4. Настройка прав sudo # Дадим пользователю ubuntu возможность выполнять команды sudo без пароля:
sudo visudo\rДобавим строку:
ubuntu ALL=(ALL:ALL) NOPASSWD: ALL\r5. Обновление системы и установка Docker # Обновим систему и установим зависимости:
sudo apt update -y\rsudo apt upgrade -y\rsudo apt install -y git apt-transport-https ca-certificates curl software-properties-common nginx\rДобавим репозиторий Docker:
sudo install -m 0755 -d /etc/apt/keyrings\rsudo curl -fsSL https://download.docker.com/linux/ubuntu/gpg -o /etc/apt/keyrings/docker.asc\rsudo chmod a+r /etc/apt/keyrings/docker.asc\recho &quot;deb [arch=$(dpkg --print-architecture) signed-by=/etc/apt/keyrings/docker.asc] \\\rhttps://download.docker.com/linux/ubuntu \\\r$(. /etc/os-release &amp;&amp; echo &quot;$VERSION_CODENAME&quot;) stable&quot; | \\\rsudo tee /etc/apt/sources.list.d/docker.list &gt; /dev/null\rУстановим Docker:
sudo apt update -y\rsudo apt install -y docker-ce\rsudo usermod -aG docker \${USER}\rnewgrp docker\rsudo systemctl status docker\r6. Настройка брандмауэра и установка Nginx # Активируем и настроим UFW:
sudo ufw enable\rsudo ufw allow 2222\rsudo ufw allow 'Nginx Full'\rsudo ufw reload\rsudo systemctl enable --now ufw\rsudo systemctl status ufw\rsudo /usr/lib/systemd/systemd-sysv-install enable ufw\r7. Установка Dockge # Dockge — это удобный веб-интерфейс для управления Docker-контейнерами. Настроим его:
mkdir -p docker/dockge/data\rcd docker/dockge\rnano compose.yml\rСодержимое compose.yml:
# version: &quot;3.3&quot;\rservices:\rdockge:\rcontainer_name: dockge\rimage: louislam/dockge:latest\rrestart: unless-stopped\rports:\r- 5001:5001\rvolumes:\r- /var/run/docker.sock:/var/run/docker.sock\r- ./data:/app/data\r- /home/ubuntu/docker:/opt/stacks\renvironment:\r- DOCKGE_STACKS_DIR=/opt/stacks\rЗапустим контейнер:
docker compose up -d\rПроверим состояние и IP-адрес контейнера:
docker ps\rdocker inspect -f '{{range.NetworkSettings.Networks}}{{.IPAddress}}{{end}}' dockge\r8. Настройка UFW для Docker # Docker по умолчанию игнорирует UFW, поэтому установим ufw-docker для управления портами контейнеров:
sudo wget -O /usr/local/bin/ufw-docker https://github.com/chaifeng/ufw-docker/raw/master/ufw-docker\rsudo chmod +x /usr/local/bin/ufw-docker\rsudo ufw-docker install\rsudo systemctl restart ufw\rsudo ufw-docker allow dockge\rЕсли нужно удалить правило или отключить ufw-docker:
sudo ufw-docker delete allow dockge\r# CTRL+K, Удалите строки между # BEGIN UFW AND DOCKER и # END UFW AND DOCKER\rsudo nano /etc/ufw/after.rules\rsudo reboot\rsudo rm /usr/local/bin/ufw-docker\r9. Проверка состояния # Проверим открытые порты и сеть:
ss -tulpn\rip a\rdocker ps\r10. Uptime-kuma # mkdir ~/docker/uptime-kuma\rcd ~/docker/uptime-kuma\rnano compose.yaml\r# version: &quot;3.3&quot;\rservices:\ruptime-kuma:\rrestart: always\rports:\r- 3001:3001\rvolumes:\r- uptime-kuma:/app/data\rcontainer_name: uptime-kuma\rimage: louislam/uptime-kuma:latest\rnetworks: []\rvolumes:\ruptime-kuma: {}\rnetworks: {}\r# запуск\rdocker compose up -d\r# остановка\rdocker compose down\rЗаключение # Теперь сервер Ubuntu 24.04 настроен с безопасным SSH-доступом, Docker, Nginx и Dockge. UFW защищает сеть, а Dockge упрощает управление контейнерами через веб-интерфейс на порту 5001. Эта конфигурация идеально подходит для развертывания современных приложений в контейнерах с базовой защитой и удобством администрирования.
Читайте также # Настройка Nginx и Docker Portainer — reverse proxy и управление контейнерами Медиа-сервер в Docker — автоматизация загрузки фильмов и сериалов `}),e.add({id:2,href:"/posts/rclone/",title:"Настройка и использование Rclone для работы с облачными хранилищами",description:"Rclone: Монтирование облачных хранилищ, синхронизация и управление файлами. Пошаговое руководство по использованию Rclone для работы с Google Drive, Yandex Disk и другими облачными провайдерами.",content:`Rclone — это мощный инструмент для управления облачными хранилищами, который поддерживает множество провайдеров, включая Google Drive, Yandex Disk, Dropbox и другие. В этом посте я расскажу, как настроить Rclone, монтировать облачные хранилища и использовать его для синхронизации и управления файлами.
Официальный сайт Rclone Руководство по настройке Rclone VFS и MergerFS Настройка Rclone # Для монтирования облачных хранилищ с опцией --allow-other необходимо раскомментировать строку в файле /etc/fuse.conf:
sudo nano /etc/fuse.conf\rНайдите строку #user_allow_other и уберите комментарий:
user_allow_other\rСоздайте директорию для монтирования облачного хранилища:
mkdir -p ~/clouds/google\rЗапустите конфигурацию Rclone:
rclone config\rСледуйте инструкциям, чтобы добавить облачное хранилище (например, Google Drive).
Монтирование # Монтирование Google Drive:
rclone mount google:/ ~/clouds/google \\\r--umask 002 \\\r--allow-other \\\r--allow-non-empty \\\r--vfs-cache-mode full \\\r--vfs-cache-max-age 24h \\\r--vfs-cache-max-size 4G \\\r--vfs-read-chunk-size 40M \\\r--vfs-read-chunk-size-limit 512M \\\r--dir-cache-time 12h \\\r--buffer-size 64M \\\r--log-level INFO \\\r--log-file ~/clouds/rclone.log \\\r--daemon\rРазмонтирование # Чтобы размонтировать облачное хранилище, используйте:
fusermount -u ~/clouds/google\rПроверка монтирования # Список удалённых хранилищ:
rclone listremotes\rПросмотр содержимого:
rclone lsd google:/\rrclone tree google:/\rИнформация о хранилище:
rclone about google:/\r# размер файлов\rrclone size synology_c2:ctlos\r# через ncdu\rrclone ncdu synology_c2:ctlos\rОчистка корзины # rclone cleanup google:/ -q\rКопирование и синхронизация файлов # Копирование между облаками
rclone copy google:/ yandex:/ -P\rКопирование из облака на локальный диск
rclone copy google:/data ~/data -P\rПеремещение файлов
rclone move ~/data google:/data --delete-empty-src-dirs\rСинхронизация # Синхронизация локальной директории с облаком:
rclone sync ~/data google:/data --create-empty-src-dirs\rСинхронизация между облаками:
rclone sync yandex:/ google:/\rДругие команды # Создание директории:
rclone mkdir google:/new_folder\rУдаление файлов:
rclone delete google:/path # Удаляет только файлы\rrclone purge google:/path # Удаляет всё, включая директории\rПоиск дубликатов:
rclone dedupe google:/path\rПроверка совпадения файлов:
rclone check ~/data google:/data\rВеб-интерфейс Rclone # Для управления Rclone через веб-интерфейс запустите:
rclone rcd --rc-web-gui\rНастройка автозапуска # Создание юнита systemd ~/.config/systemd/user/rclone-mount@.service:
nano ~/.config/systemd/user/rclone-mount@.service\rДобавьте следующий контент:
[Unit]\rDescription=RClone multiple Mount Service\rWants=network-online.target\rAfter=network-online.target\r[Service]\rType=notify\r# Создаем папку перед запуском\rExecStartPre=-/usr/bin/mkdir -p %h/clouds/%i\r# Каждая строка/параметр ниже (кроме последней) заканчивается на &quot; \\&quot;\r# --log-file %h/clouds/rclone.log\rExecStart=/usr/bin/rclone mount %i:/ %h/clouds/%i \\\r--config %h/.config/rclone/rclone.conf \\\r--umask 002 \\\r--allow-other \\\r--allow-non-empty \\\r--vfs-cache-mode full \\\r--vfs-cache-max-age 24h \\\r--vfs-cache-max-size 4G \\\r--vfs-read-chunk-size 40M \\\r--vfs-read-chunk-size-limit 512M \\\r--dir-cache-time 12h \\\r--buffer-size 64M \\\r--log-level INFO\rExecStop=/usr/bin/fusermount -uz %h/clouds/%i\rRestart=on-failure\rRestartSec=10\r[Install]\rWantedBy=default.target\rЗапуск и включение сервиса # Перезагрузите systemd и включите автозапуск:
systemctl --user daemon-reload\rsystemctl --user enable --now rclone-mount@&lt;rclone-remote&gt;\rЗамените &lt;rclone-remote&gt; на имя вашего удалённого хранилища (например, google).
Итог # Rclone — это универсальный инструмент для работы с облачными хранилищами. С его помощью можно легко монтировать облачные диски, синхронизировать данные и управлять файлами. Настройка через systemd позволяет автоматизировать процесс монтирования при загрузке системы.
Читайте также # Backup в Linux: Restic, Borg, Kopia — сравнение инструментов резервного копирования Настройка медиа-сервера в Docker — автоматизация загрузки фильмов с торрентов `}),e.add({id:3,href:"/posts/wire-hole/",title:"Wireguard, pihole, unbound | предотвращаем утечку dns",description:"Настройка WireGuard + Pi-hole + Unbound для приватного DNS без утечек. Полная конфигурация VPN-сервера с блокировкой рекламы.",content:`Смотри видео с детальной настройкой youtube.com.
45.138.72.135\rroot\r747AuBOZ7WNt\runbound wireguard pihole apt install wg...\rwget https://raw.githubusercontent.com/burghardt/easy-wg-quick/master/easy-wg-quick\rchmod +x easy-wg-quick\r./easy-wg-quick\rsudo cp wghub.conf /etc/wireguard/wghub.conf\rsudo systemctl enable --now wg-quick@wghub\r# new client\r./easy-wg-quick bla\rsudo cp -r wghub.conf /etc/wireguard/wghub.conf\rsudo systemctl restart wg-quick@wghub\rsudo wg-quick down ./wghub.conf # if already configured\rsudo wg-quick up ./wghub.conf\rsudo wg show\r# sudo nano /etc/sysctl.conf\rnet.core.default_qdisc = fq\rnet.ipv4.tcp_congestion_control = bbr\rnet.ipv4.ip_forward = 1\rnet.ipv4.conf.default.rp_filter = 1\rnet.ipv4.conf.all.rp_filter = 1\rnet.ipv4.tcp_syncookies = 1\r# sudo sysctl -p\rsudo cat /etc/wireguard/wghub.conf\r# open port\rcurl -o /var/lib/unbound/root.hints https://www.internic.net/domain/named.cache\r# mv access-control: 10.134.99.0/24 &gt; wg network | ip a\r# sudo nano /etc/unbound/unbound.conf.d/pi-hole.conf\rserver:\r# if no logfile is specified, syslog is used\r# logfile: &quot;/var/log/unbound/unbound.log&quot;\rverbosity: 1\rport: 5353\rdo-ip4: yes\rdo-udp: yes\rdo-tcp: yes\r# may be set to yes if you have IPv6 connectivity\rdo-ip6: no\r# use this only when you downloaded the list of primary root servers\rroot-hints: &quot;/var/lib/unbound/root.hints&quot;\r# respond to DNS requests on all interfaces\rinterface: 0.0.0.0\rmax-udp-size: 3072\r# IPs authorised to access the DNS Server\raccess-control: 0.0.0.0/0 refuse\raccess-control: 127.0.0.1 allow\raccess-control: 10.134.99.0/24 allow\r# hide DNS Server info\rhide-identity: yes\rhide-version: yes\r# limit DNS fraud and use DNSSEC\rharden-glue: yes\rharden-dnssec-stripped: yes\rharden-referral-path: yes\r# add an unwanted reply threshold to clean the cache and avoid, when possible, DNS poisoning\runwanted-reply-threshold: 10000000\r# have the validator print validation failures to the log val-log-level: 1\r# don't use Capitalisation randomisation as it known to cause DNSSEC issues sometimes\r# see https://discourse.pi-hole.net/t/unbound-stubby-or-dnscrypt-proxy/9378 for further details\ruse-caps-for-id: no\r# reduce EDNS reassembly buffer size\r# suggested by the unbound man page to reduce fragmentation reassembly problems\redns-buffer-size: 1472\r# TTL bounds for cache\rcache-min-ttl: 3600\rcache-max-ttl: 86400\r# perform prefetching of close to expired message cache entries\r# this only applies to domains that have been frequently queried\rprefetch: yes\rprefetch-key: yes\r# one thread should be sufficient, can be increased on beefy machines\rnum-threads: 1\r# ensure kernel buffer is large enough to not lose messages in traffic spikes\rso-rcvbuf: 1m\r# ensure privacy of local IP ranges\rprivate-address: 192.168.0.0/16\rprivate-address: 169.254.0.0/16\rprivate-address: 172.16.0.0/12\rprivate-address: 10.0.0.0/8\rprivate-address: fd00::/8\rprivate-address: fe80::/10\rsudo systemctl enable --now unbound\r# intfs wghub\rcurl -sSL https://install.pi-hole.net | bash\rhttp://ip/admin\r# Settings - DNS наш Unbound 127.0.0.1#5353\r# open port 5353\rdig pi-hole.net @127.0.0.1 -p 5353 # NOERROR\rdig sigok.verteiltesysteme.net @127.0.0.1 -p 5353\rdig sigfail.verteiltesysteme.net @127.0.0.1 -p 5353 # SERFAIL\r# wg client conf dns &gt; wghub | ip a\r# wg\rnano intnetdns.txt\r# replace ip 1.1.1.1 default &gt; wghub ip : 10.148.135.1\r# dns wghub ip : 10.148.135.1\r# 10: 10 &gt; wgclient_10.conf\r[Interface]\rAddress = 10.148.135.10/24\rDNS = 10.148.135.1\rPrivateKey = oBj9b47cvZaGaCdHQUl1tu6in6L4yoL8hXxUd1EpU1c=\rMTU = 1280\r[Peer]\rPublicKey = G7VcOHBqXYFPppKNUZ25RJLjEXEDq+Gsn/jmczX5HB0=\rPresharedKey = LDgByqF8J/TgBI9vE+17aRNWnlJwQoD6i6xZCbwbdBk=\rAllowedIPs = 0.0.0.0/0, ::/0\rEndpoint = 45.138.72.135:44828\rPersistentKeepalive = 25\r# open ports\rufw allow ssh\rufw allow 44828/udp\r# net\rufw allow 80/tcp\rufw allow 53/udp\r# wg\rsudo ufw allow from 10.134.99.0/24 to any port 80\rsudo ufw allow from 10.134.99.0/24 to any port 53\rsudo ufw reject https\rss -tulpn\r45.138.72.135/admin http://pi.hole/admin https://dnsleak.com Читайте также # VPN сервер в Linux — WireGuard, SSH-туннель, Sshuttle Tor проксирование в Arch Linux — настройка onion-трафика `}),e.add({id:4,href:"/posts/tor/",title:"Tor проксирование",description:"Настройка проксирования onion-трафика через Tor в Arch Linux: dnsmasq, dhcpcd, iptables. Пошаговая инструкция для доступа к .onion сайтам.",content:`Эта настройка позволяет обращаться к .onion адресам напрямую из браузера, не используя Tor Browser. Все запросы к onion-сайтам будут проходить через Tor, а остальной трафик останется обычным. В этом деле поможет dnsmasq, но заставить его работать я смог только с dhcpcd, не знаю возможно ли это сделать через networkmanager, не пользуюсь им. Выключаем и удаляем все сетевое, ставим dnsmasq и dhcpcd.
sudo pacman -S dnsmasq dhcpcd tor\rКонфиг dnsmasq.
# /etc/dnsmasq.conf\rno-resolv\rno-hosts\rport=53\rserver=127.0.0.1#9053\rlisten-address=::1,127.0.0.1\rserver=/onion/127.0.0.1#9053\rserver=/.exit/127.0.0.1#9053\rserver=8.8.8.8\rserver=8.8.4.4\rКонфиг dhcpcd.
# /etc/dhcpcd.conf\rnohook resolv.conf\rnoarp\rКонфиг tor. tor_resolv походу не обязательно.
# /etc/tor/torrc\rVirtualAddrNetwork 10.254.0.0/16\rAutomapHostsOnResolve 1\rAutomapHostsSuffixes .exit,.onion\rTransPort 127.0.0.1:9040 NoIsolateClientAddr SessionGroup=1\rDNSPort 127.0.0.1:9053\rServerDNSResolvConfFile /etc/tor_resolv.conf\r# /etc/tor_resolv.conf\rnameserver 8.8.8.8\rВыключам, включаем и стартуем службы.
sudo systemctl disable --now systemd-networkd.socket\rsudo systemctl disable --now systemd-networkd\rsudo systemctl disable --now systemd-resolved\rsudo systemctl enable --now dhcpcd\rsudo systemctl enable --now dnsmasq\rsudo systemctl start tor\rПравила перенаправления запросов onion в тор мост.
# ip route show default | awk '/default/ {print $5}'\rsudo iptables -t nat -A PREROUTING -d 10.254.0.0/16 -i enp5s0 -p tcp -j REDIRECT --to-ports 9040\rsudo iptables -t nat -A OUTPUT -d 10.254.0.0/16 -p tcp -j REDIRECT --to-ports 9040\rВыключить запрет в firefox. В адресной строке откройте адрес about:config и выключить значение.
network.dns.blockDotOnion false\rДля теста onion keybase.
keybase5wmilwo
Если все нормально, то можно выгрузить правила iptables в любое удобное место, я сохраню рядом с дефолтом.
# /etc/iptables/iptables.rules\rsudo iptables-save -f /etc/iptables/iptables.rules.tor\rЕсли нужны эти правила постоянно, то просто перетрите /etc/iptables/iptables.rules, но перед этим создайте копию.
sudo cp /etc/iptables/iptables.rules /etc/iptables/iptables.rules.bak\rsudo iptables-save -f /etc/iptables/iptables.rules\rСчитывание правил с файла.
sudo iptables-restore /etc/iptables/iptables.rules.bak\rЗаворачивание всего трафика в tor # В сети наткнулся на простой пайтон скрипт, немного подправил под Arch.
toriptables3.py
sudo toriptables3.py -l\r# сброс правил\rsudo toriptables3.py -f\r# лучше откатите через iptables\rsudo iptables-restore /etc/iptables/iptables.rules.bak\r# help\rsudo toriptables3.py -h\rСсылки # TransparentProxy iptables Dhcpcd Using_TorDNS_for_all_DNS_queries Dnsmasq Читайте также # Psiphon в Linux: обход блокировок — ещё один способ обойти цензуру VPN сервер в Linux — настройка собственного VPN `}),e.add({id:5,href:"/posts/weechat/",title:"Настройка и использование weechat в linux",description:"Настройка WeeChat в Linux: подключение к IRC (Libera.Chat), регистрация ника, Matrix, мосты и скрипты.",content:`Weechat — консольный чат клиент для irc сетей и не только, weechat about.
Установка # yay -S weechat\rЗапуск.
weechat\rОсновные команды # # записать изменения в конфиги\r/save\r# перезагрузить\r/reload\r# выход\r/quit\r# изменения значений, через\r/set\r# показ значений, типо справка\r/fset\rПодключение к сети Libera # Настройка подключения к irc сети Libera.Chat. Актуальные данные для подключения уточняйте на их сайте, порт и хост. libera.chat guides.
После запуска weechat, конфиги пользователя инициализируются в ~/.config/weechat вручную менять их не рекомендуется, все делаем через /команды. Добавляем сервер. Стоит отметить, что серверов может быть много, можно добавить и другие таким же макаром.
/server add libera irc.libera.chat/6697 -ssl\rНики и имя.
/set irc.server.libera.nicks &quot;creio,cretm,mynick3,mynick4,mynick5&quot;\r/set irc.server.libera.username &quot;creio&quot;\r/set irc.server.libera.realname &quot;Alex Creio&quot;\rРегистрация в libera # Довольно неплохо написано на их сайте, но я все же опишу.
libera.chat guides registration
# подключиться к серверу\r/connect libera\r# присвойте основной ник\r/nick YourNick\r# дополнительный\r/nick YourNick2\rРегистрация ника. Придумайте пароль и укажите реальные email, на него придет подтверждение, которое нужно запустить.
/msg NickServ REGISTER YourPassword youremail@example.com\rПосле подтверждения вход в учетку.
/msg NickServ IDENTIFY YourNick YourPassword\r# привязка\r/msg NickServ GROUP\rЧистый вход. Подключение к серверу и авторизация.
/connect irc.libera.chat 6667 YourNick:YourPassword\rЕсли подключены к серверу, но не авторизованы.
/msg NickServ IDENTIFY YourNick YourPassword\rНиже описан процесс сохранения данных в конфиг.
Подключение # В чистый weechat с имеющейся учетной записью.
/set irc.server.libera.autoconnect on\r/set irc.server.libera.sasl_username &quot;creio&quot;\r/set irc.server.libera.sasl_password &quot;xxxxxxx&quot;\r# автовход в чат(ы), через запятую\r/set irc.server.libera.autojoin &quot;#ctlos&quot;\r# сохранить\r/save\r# подключить\r/connect libera\rБолее подробное руководство по настройки подключения.
Дополнительные команды # Вход, выход, отключение, сообщения.
# Зайти на канал\r/join #ctlos\r# Покинуть канал (оставляет буфер)\r/part [quit message]\rЗакрыть соединение с сервером, каналом или буфером\r/close\r# Отключиться от сервера, на серверном буфере\r/disconnect\r# Открыть буфер и отправить сообщение пользователю (с псевдонимом foo):\r/query foo сообщение\r# Закрыть буфер\r/close\rПодключение к matrix # Matrix отдельный сервер, точнее целая сеть, проще всего создать аккаунт через веб интерфейс riot.im(element), а затем уже его прописать в weechat. В репозитории лежит пакет weechat-matrix, но он криво работает, поэтому ставим rs.
yay -S weechat-matrix-rs-git\rДобавляем сервер и настраиваем подключение.
/matrix server add matrix_org https://matrix.org/\r/set matrix-rust.server.matrix_org.autoconnect on\r/set matrix-rust.server.matrix_org.ssl_verify on\r/set matrix-rust.server.matrix_org.username johndoe\r/set matrix-rust.server.matrix_org.password Mypassword\r/matrix connect matrix_org\r/save\rИзменение интерфейса # Чаты(каналы) и серверы образуют буферы(вкладки), переключать их Alt + цифра или Alt + (вверх,вниз). Отключить автоматическое совмещение буферов сервера.
# default: merge_with_core\r/set irc.look.server_buffer independent\rУменьшить ники и буферы по ширине.
/set weechat.bar.buflist.size_max 20\r/set weechat.look.prefix_align_max 15\r/bar set nicklist size_max 15\r/bar set nicklist size 15\rВключить мышь, после этого копирование работает с удерживанием Shift.
/mouse enable\r/save\rСкрипты.
/set weechat.plugin.autoload &quot;*,!guile,!javascript,!lua,!php,!tcl,!perl,!ruby,!fifo,!xfer&quot;\r/set script.scripts.download_enabled on\r/script install autosort.py\r/save\r/script\rКлавиши PageUp/PageDown скролл истории чата, Alt+l переключение ленты чата на все окно. Остальное в документации :).
Настраивается абсолютно все, постарался в данное руководство воткнуть самый минимум для старта и более-менее комфортного использования, а также не забывайте, что матричные чаты можно юзать и в браузере, как и некоторые irc.
Не забудь заглянуть в чаты Ctlos Linux:
Matrix Matrix Libera Web Kiwiirc /join #ctlos\rПодключение через Matrix # Авторизовавшись через web морду, например riot.im(element) по ссылкам выше, можно войти практически в любой irc сервер под своими учетными данными, через мосты, так сервисы крупных irc сетей уже присутствуют в матриксе, покажу на примере libera. Откройте диалоги с ботами @appservice:libera.chat и @NickServ:libera.chat, просто начните с ними чат.
Первой командой вы меняете ник, сообщаете серверу, что это вы.
# команда|server|ник\r!nick irc.libera.chat YourNick\r# в ответе\r# Nick changed from 'YourNick[m]' to 'YourNick'\rПеречисление чатов к которым вы подключены на сервере libera, их мосты, если таковые имеются.
!listrooms\rДля авторизации перейдите к боту @NickServ:libera.chat, тут все по аналогии, выше писал о создании учетки и логине, отличие только в опускании начала команды /msg NickServ.
identify YourNick YourPassword\r# должен появиться диалог SaslServ (PM on irc.libera.chat) с инфо о логине\rinfo\rstatus\racc YourNick\r# ответ acc 3, значит все ок\rРегистрация и подтверждение кода через почту.
register YourPassword your@email.com\r# код с почты\rverify register YourNick verification-code\rinfo\rТеперь возвращайтесь к боту @appservice:libera.chat для настройки автоматической авторизации.
!username YourNick\r# ответ Successfully\r!storepass YourPassword\r# ответ Successfully\r# переподключить\r!reconnect\r# информация\r!whois YourNick\r# список чатов данного моста\r!listrooms\rМосты работают с небольшой задержкой и в интерфейсе матрикса форматирование мешает, но можно выбрать простой текст:
/plain !join #ctlos\rЕсли вы хотите войти без моста с учеткой матрикса, то просто подставьте в адресной строке #ctlos:libera.chat
https://riot.im/app/#/room/#ctlos:libera.chat\r`}),e.add({id:6,href:"/posts/firewall/",title:"Firewall в linux | iptables | ufw",description:"Базовая настройка файрвола в Linux: установка UFW, управление портами, разрешение SSH. Решение проблем с netfilter-persistent на Ubuntu.",content:`Firewall — межсетевой экран. UFW (Uncomplicated Firewall) — простая обёртка над iptables, которая упрощает управление правилами. Просмотр инфы по портам, в пакете iproute2.
ss -tulpn\rСамый распространенный iptables, над ним как правило уже обертки, типо ufw. Я использую ufw, так как не нужно городить огромные команды, как это происходит в чистом iptables.
Ufw # Пакет есть в любом дистрибутиве. Предварительно включаем ssh, так как может порвать связь, а по дефолту все закрыто.
Установка и включение # sudo pacman -S ufw\rsudo ufw allow ssh\rsudo ufw enable\rsudo systemctl enable --now ufw.service\rИспользование # Присутствуют готовые правила, как ssh, а также можно указывать порты и протокол прямо 8080/tcp.
# справка\rsudo ufw help\r# статус\rsudo ufw status\r# перезагрузка\rsudo ufw reload\r# выключение\rsudo ufw disable\r# открыть порт/протокол\rsudo ufw allow 8000/tcp\rsudo ufw allow 8000/udp\rUbuntu 20.04 # В юбунте встретил netfilter-persistent и он перебивал ufw. Соответственно выключаем его и делаем очистку flush, перезагружаем ufw.
# правила, до\rsudo iptables -L\rsudo systemctl disable --now netfilter-persistent.service\rsudo netfilter-persistent flush\rsudo ufw reload\rsudo systemctl restart ufw.service\rsudo systemctl status ufw.service\r# правила, после\rsudo iptables -L\rЧитайте также # Настройка сервера Ubuntu 24.04 с Docker — полная настройка сервера с UFW Настройка Nginx и Docker Portainer — reverse proxy и управление контейнерами `}),e.add({id:7,href:"/posts/transmission/",title:"Transmission — раздача торрентов со своего сервера",description:"Настройка Transmission-daemon для раздачи торрентов со своего сервера: установка, конфигурация, Docker и скрипт создания torrent-файлов.",content:`Установка transmission-daemon # Установка, копирование конфигов в директорию юзера и создание нужных директорий.
sudo apt update &amp;&amp; sudo apt upgrade -y\rsudo apt install transmission-daemon -y\rsudo systemctl stop transmission-daemon\rsudo cp -R /etc/transmission-daemon ~/.config/\rsudo chown -R $USER ~/.config/transmission-daemon\rmkdir ~/Torrents\rmkdir -p ~/Downloads/.incomplete\rnano ~/.config/transmission-daemon/settings.json\rКонфигурация демана # В rpc-whitelist укажите свой ip, узнать curl ident.me, можно указать маску ..., но это откроет веб морду для любого ip. Создайте хороший пароль если будете открывать веб морду по маске.
&quot;download-dir&quot;: &quot;/home/ubuntu/Downloads&quot;,\r&quot;incomplete-dir&quot;: &quot;/home/ubuntu/Downloads/.incomplete&quot;,\r&quot;incomplete-dir-enabled&quot;: true,\r&quot;rpc-authentication-required&quot;: false,\r&quot;rpc-password&quot;: &quot;pass&quot;,\r&quot;rpc-username&quot;: &quot;admin&quot;,\r&quot;rpc-whitelist&quot;: &quot;127.0.0.1,100.123.10.170&quot;,\r&quot;watch-dir&quot;: &quot;/home/ubuntu/Torrents&quot;,\r&quot;watch-dir-enabled&quot;: true\rОписание всех настроек settings.json.
nastrojka-transmission-daemon-settings-json/
Системная конфигурация # Меняем рабочего юзера и значения памяти sysctl.
# rename user\rsudo nano /etc/systemd/system/multi-user.target.wants/transmission-daemon.service\rsudo systemctl daemon-reload\rsudo systemctl start transmission-daemon\rsudo systemctl status transmission-daemon\recho &quot;net.core.rmem_max = 4194304&quot; | sudo tee -a /etc/sysctl.d/50-transmission-daemon.conf\recho &quot;net.core.wmem_max = 1048576&quot; | sudo tee -a /etc/sysctl.d/50-transmission-daemon.conf\rsudo sysctl --system\rsudo systemctl restart transmission-daemon\rsudo systemctl status transmission-daemon\rПроброс порта ssh # ssh -L 9091:127.0.0.1:9091 ubuntu@193.122.8.187 -N\rЭкспорт PATH # Добавляем путь для скриптов.
echo &quot;export PATH=$HOME/.local/bin:$PATH&quot; &gt;&gt; ~/.bashrc\rsource ~/.bashrc\rОткрыть порты # # open port\r51413/tcp\r51413/udp\rПорт 9091/tcp открывать если нужен доступ к веб морде и создайте хороший пароль в таком случае. В ufw.
sudo ufw allow 51413/tcp\rsudo ufw allow 51413/udp\r# sudo ufw allow 9091/tcp\rsudo ufw reload\rsudo ufw status\rСкрипт создания torrent файла # mkdir ~/.local/bin\rnano ~/.local/bin/transmission.sh\r#!/bin/bash\r## transmission.sh /file_name.iso /torrent_file.iso.torrent\r# Last update 2021/10/04\r# https://github.com/ngosang/trackerslist\r# https://ngosang.github.io/trackerslist/trackers_best.txt\rTRANSDIR=$HOME/Downloads\rcp -r $1 $TRANSDIR\rtransmission-create $1 -c &quot;https://ctlos.github.io/changelog/&quot;\r-t http://p4p.arenabg.com:1337/announce\r-t udp://tracker.opentrackr.org:1337/announce\r-t udp://9.rarbg.com:2810/announce\r-t udp://tracker.openbittorrent.com:6969/announce\r-t http://tracker.openbittorrent.com:80/announce\r-t http://openbittorrent.com:80/announce\r-t udp://exodus.desync.com:6969/announce\r-t udp://www.torrent.eu.org:451/announce\r-t udp://tracker.torrent.eu.org:451/announce\r-t udp://tracker.tiny-vps.com:6969/announce\r-t udp://retracker.netbynet.ru:2710/announce\r-t udp://retracker.lanta-net.ru:2710/announce\r-t udp://opentor.org:2710/announce\r-t udp://open.stealth.si:80/announce\r-t udp://camera.lei001.com:6969/announce\r-t udp://bt2.archive.org:6969/announce\r-t udp://bt1.archive.org:6969/announce\r-t https://tracker.nitrix.me:443/announce\r-t https://tracker.nanoha.org:443/announce\r-t https://tracker.lilithraws.cf:443/announce\r-o $2\rtransmission-remote -a $2\rКоманды ниже: листинг, удаление, справка.
transmission-remote -l\rtransmission-remote -t 1 -rad\rtransmission-remote -h\rАвторизация по паролю, если не отключили &ldquo;rpc-authentication-required&rdquo;: true,.
transmission-remote --auth admin:pass\rПросмотр инфы по портам.
ss -tulpn\rDocker # Установка зависимостей, docker, docker-compose в ubuntu minimal.
sudo apt update &amp;&amp; sudo apt upgrade -y\rsudo apt -y install apt-transport-https software-properties-common ca-certificates curl iproute2 gnupg\rgit ufw bash-completion htop nano tmux\rcurl -fsSL https://download.docker.com/linux/debian/gpg | sudo apt-key add -\rsudo add-apt-repository &quot;deb [arch=amd64] https://download.docker.com/linux/ubuntu $(lsb_release -cs) stable&quot;\rsudo apt update &amp;&amp; sudo apt-cache policy docker-ce\rsudo apt install docker-ce docker-ce-cli containerd.io -y\rdc_version=$(curl -s &quot;https://github.com/docker/compose/releases/latest&quot; | sed 's#.*tag/(.*)&quot;.*#1#')\rsudo curl -L &quot;https://github.com/docker/compose/releases/download/$dc_version/docker-compose-$(uname -s)-$(uname -m)&quot; -o /usr/local/bin/docker-compose\rsudo chmod +x /usr/local/bin/docker-compose\rsudo ln -s /usr/local/bin/docker-compose /usr/bin/docker-compose\rsudo su\rpasswd\rpasswd ubuntu\rexit\rsudo usermod -aG docker \${USER}\rsu - \${USER}\rsudo systemctl enable --now docker\rОбязательно нужно создать подкачку, если облако не сделало это автоматически, пример создания swapfile.
sudo fallocate -l 4G /swapfile\rsudo chmod 600 /swapfile\rsudo mkswap /swapfile\rsudo swapon /swapfile\rsudo swapon --show\rИ добавляем в /etc/fstab.
echo '/swapfile none swap sw 0 0' | sudo tee -a /etc/fstab\rБерем готовый compose файл docs.linuxserver.io/images/docker-transmission. Создаем рабочие директории, переходим в него и создаем композ файл.
mkdir -p ~/docker-transmission/{config,downloads,watch}\rcd ~/docker-transmission\rnano docker-compose.yml\rПоменяйте переменные, id покажет uid, gid.
---\rversion: &quot;2.1&quot;\rservices:\rtransmission:\rimage: lscr.io/linuxserver/transmission\rcontainer_name: transmission\renvironment:\r- PUID=1000\r- PGID=1000\r- TZ=Europe/Moscow\r- USER=admin #optional\r- PASS=pass #optional\r- WHITELIST=iplist #optional\rvolumes:\r- ./config:/config\r- ./downloads:/downloads\r- ./watch:/watch\rports:\r- 9091:9091\r- 51413:51413\r- 51413:51413/udp\rrestart: unless-stopped\rЗапуск.
docker-compose up -d\rВойти в контейнер.
docker exec -it transmission /bin/bash\rЛог.
docker logs -f transmission\rОстановка, перейти в директорию.
cd ~/docker-transmission\rdocker-compose down\rОбновление.
cd ~/docker-transmission\rdocker-compose down\rdocker-compose pull transmission\rdocker-compose up -d\r# удаление старых образов\rdocker image prune\rОтключаем видимость ip при ssh логине.
sudo nano /etc/ssh/sshd_config\rPrintLastLog no\rsudo systemctl restart sshd\rЧитайте также # Настройка медиа-сервера в Docker — Radarr, Sonarr, Jackett, qBittorrent Настройка сервера Ubuntu 24.04 — Docker, Nginx, UFW `}),e.add({id:8,href:"/posts/media-server/",title:"Настройка автоматической загрузки фильмов с торрентов",description:"Автоматическая загрузка фильмов с торрентов: связка Radarr + Sonarr + Jackett + qBittorrent + Telegram-бот в Docker.",content:`Все будет проделано из под Arch Linux, но суть везде одна, весь этот софт есть и под windows.
odysee.com Второе видео Третье Задача: Максимально автоматизировать процесс скачивания как новых фильмов, так и существующих.
Конечный результат, заходим на Imdb(авторизация), добавляем нужный фильм в список и на выходе получаем нужное в директории Films. Второй вариант, заходим в телеграм, отправляем боту название фильма и на выходе получаем нужное.
Исследовав этот вопрос в могучем гугле, вырисовывается простой вариант с использованием связки в docker, статей на данную тему не много, но их достаточно, даже с примерами композ файлов, собственно америку не открываем, а используем и попутно вникаем в настройку, которая не раскрыта в полной мере.
Radarr/Sonarr - это менеджер коллекций фильмов/сериалов. Imdb - список отслеживания. Jackett - менеджер торрент трекеров. Qbittorrent - торрент клиент. Gramarr - телеграм бот. Portainer docker # Установим docker и веб морду для удобства администрирования. Об этом я уже писал.
sudo pacman -S docker-compose\rsudo usermod -aG docker \${USER}\rsu - \${USER}\rsudo systemctl start docker\rdocker volume create portainer_data\rdocker run -d --network host --name=portainer --restart=always -v /var/run/docker.sock:/var/run/docker.sock -v portainer_data:/data portainer/portainer-ce\rПортайнер работает на http://localhost:9000.
Настраиваем контейнеры # Создаем нужные директории, compos файл.
mkdir -p ~/docker-app/mediaserver\rcd ~/docker-app/mediaserver\rmkdir -p ./{downloadclient-downloads,radarr,sonarr,qbittorrent,jackett,gramarr,TV,Films}\rСоздаем докер сеть.
docker network create -d bridge --subnet=172.23.0.0/24 --gateway 172.23.0.1 media-proxy\rСоздаем сценарий. Узнаем PUID/PGID командой id и вставляем следующее заменив только id.
nano docker-compose.yml\r---\rversion: &quot;2&quot;\rservices:\rsonarr:\rimage: linuxserver/sonarr\rnetworks:\rdefault:\ripv4_address: 172.23.0.51\rcontainer_name: sonarr\renvironment:\r- PUID=1000\r- PGID=985\r- TZ=Europe/Moscow\r- UMASK_SET=022 #optional\rvolumes:\r- ./sonarr:/config\r- ./TV:/tv\r- ./downloadclient-downloads:/downloads\rports:\r- 6001:8989\rrestart: unless-stopped\rradarr:\rimage: linuxserver/radarr\rnetworks:\rdefault:\ripv4_address: 172.23.0.52\rcontainer_name: radarr\renvironment:\r- PUID=1000\r- PGID=985\r- TZ=Europe/Moscow\r- UMASK_SET=022 #optional\rvolumes:\r- ./radarr:/config\r- ./Films:/movies\r- ./downloadclient-downloads:/downloads\rports:\r- 6002:7878\rrestart: unless-stopped\rqbittorrent:\rimage: linuxserver/qbittorrent\rnetworks:\rdefault:\ripv4_address: 172.23.0.53\rcontainer_name: qbittorrent\renvironment:\r- PUID=1000\r- PGID=985\r- TZ=Europe/Moscow\r- UMASK_SET=022\r- WEBUI_PORT=6003\rvolumes:\r- ./qbittorrent:/config\r- ./downloadclient-downloads:/downloads\rports:\r- 6881:6881\r- 6881:6881/udp\r- 6003:6003\rrestart: unless-stopped\rjackett:\rimage: linuxserver/jackett\rnetworks:\rdefault:\ripv4_address: 172.23.0.54\rcontainer_name: jackett\renvironment:\r- PUID=1000\r- PGID=985\r- TZ=Europe/Moscow\r# - RUN_OPTS=run options here #optional\rvolumes:\r- ./jackett/config:/config\r- ./downloadclient-downloads:/downloads\rports:\r- 6004:9117\rrestart: unless-stopped\rgramarrru:\rimage: memodota/gramarrru\rnetworks:\rdefault:\ripv4_address: 172.23.0.55\rcontainer_name: gramarrru\rdepends_on:\r- sonarr\r- radarr\rvolumes:\r- ./gramarr/config.json:/config/config.json\rrestart: unless-stopped\rnetworks:\rdefault:\rexternal: true\rname: media-proxy\rСоздаем gramarr конфиг.
nano gramarr/config.json\rВставляем следующее. Токены будем заполнять по мере получения, пароли на ваше усмотрение. IP не меняем.
{\r&quot;telegram&quot;: {\r&quot;botToken&quot;: &quot;123123123:BBCCVVf-As-2IPSUMQy2w_HnLoReMqk&quot;\r},\r&quot;bot&quot;: {\r&quot;password&quot;: &quot;&quot;,\r&quot;adminPassword&quot;: &quot;demo&quot;\r},\r&quot;radarr&quot;: {\r&quot;hostname&quot;: &quot;172.23.0.52&quot;,\r&quot;apiKey&quot;: &quot;6brandomfb3e23&quot;,\r&quot;port&quot;: 7878,\r&quot;urlBase&quot;: &quot;&quot;,\r&quot;ssl&quot;: false,\r&quot;username&quot;: &quot;admin&quot;,\r&quot;password&quot;: &quot;pass_radarr&quot;,\r&quot;maxResults&quot;: 6\r},\r&quot;sonarr&quot;: {\r&quot;hostname&quot;: &quot;172.23.0.51&quot;,\r&quot;apiKey&quot;: &quot;1b5random29546&quot;,\r&quot;port&quot;: 8989,\r&quot;urlBase&quot;: &quot;&quot;,\r&quot;ssl&quot;: false,\r&quot;username&quot;: &quot;admin&quot;,\r&quot;password&quot;: &quot;pass_sonarr&quot;,\r&quot;maxResults&quot;: 6\r}\r}\rСобственно можно запускать и открывать на указанных портах назначаем пароли и получаем apiKey(ключи). Порты как в докер файле слева локальные, справа внутри докера(не интересуют). Стартуем находясь в директории с docker-compose.yml.
docker-compose up -d\rПереходим в portainer http://localhost:9000, на вкладку stacks и видим mediaserver, перейдя в который увидим все приложения, возможно gramarr не запустился и это нормально, просто отсюда возможно удобней делать перезапуск всех разом и видеть их статус.
Sonarr я рассматривать не буду, только базовая доступность, но он почти похож на radarr думаю разберетесь.
Sonarr: Settings - general. Radarr: Settings - general. Qbittorrent: Tools - Options - Web Ui. Меняем язык, сохраняем и перезагружаем стр. логин: admin, пароль: adminadmin, лучше поменять. Попутно добавляем данные в gramarr/config.json.
Sonarr http://localhost:6001 Radarr http://localhost:6002 Qbittorrent http://localhost:6003 Jackett http://localhost:6004 Создание бота telegram # Открываем бота @BotFather и в нем создаем своего для грамарра.
/newbot пишем имя, MMediaBot Затем ник, на конце обязательно bot, mudazvonbot. Имя может быть занято, пробуйте различные вариации. В итоге должны увидеть &ldquo;Done! &hellip;&rdquo;, ссылка http://t.me/mudazvonbot и api ключ, копировать полностью выделенный ключ и вставить в config.json. password оставляем пустым, а adminPassword назначаем он нужен в самом боте mudazvonbot, для авторизации.
&quot;telegram&quot;: {\r&quot;botToken&quot;: &quot;123123123:BBCCVVf-As-2IPSUMQy2w_HnLoReMqk&quot;\r},\r&quot;bot&quot;: {\r&quot;password&quot;: &quot;&quot;,\r&quot;adminPassword&quot;: &quot;demo&quot;\r},\rСобственно с ботом все и его конфигом, пока он не работает, так как связка еще не полна.
Настройка Jackett # Jackett http://localhost:6004
Тут только добавляем трекеры, add indexer и в поиск по очереди: Rutor, RuTracker, NoNaMe. Добавляем публичные, а еще лучше и приватные с логином и паролем semi-private(nnmclub/rutracker).
Настройка radarr # radarr http://localhost:6002
Меняем язык settings - ui, включаем вверху Show Advanced, сохраняем Save и обновляем стр.
Регаем акк на www.imdb.com, создаем и делаем список публичным, копируем ид в адресной строке ls503478540.
Идем в Настройки - Списки и добавляем список Imdb. Вставляем полученный UserId ls503478540, выбрать предпочтительный профиль качества. Остальное вроде по умолчанию, тест и сохранить. Если выставить удалить фильм и его файлы в Очистить уровень библиотеки, то когда убираем отслеживание в imdb фильм удаляется с radarr и Films, но в qbit остается.
Идем в Настройки - Клиенты для скачивания, добавляем qbit, указав логин и пароль от него, обязательно внутренний ip: 172.23.0.53 и порт: 6003. Остальное по умолчанию, тест - сохранить.
Настройки - Индексаторы, копируем листы по очередно Torznab Feed из Jackett. Один feed - одна запись в индексатор. Заполняем имя(любое, по имени трекера например - rutor), в URL вставляем скопированный feed и обязательно меняем в ссылке ip и порт на внутренний: 172.23.0.54:9117. По аналогии и с другими трекерами.
Jackett http://localhost:6004. Настройки - Профили тут просто везде поменял язык на Русский.
Конец # Перезапустить контейнеры в portainer, при добавление в список imdb(синхронит каждые 6 часов). Если все правильно, то добавление должно появиться и в радаре и в qbit.
Авторизация у бота /auth SUPERPASS, а возможности п /help. Бот также должен ответить с выборам качества и с сохранением в /movies. Да в докере это директория /movies, а локально мы ее смонтировали в Films, также и с /downloads - локально downloadclient-downloads.
После удаления из списка imdb, фильм удаляется, но вот торрент нужно удалить в qbit и он удалиться и из downloadclient-downloads, qbit http://localhost:6003/.
Принудительно считать imdb list, можно повесить на крон. В apikey= поставить ключ radarr.
curl -X POST &quot;http://localhost:6002/api/v3/command?apikey=6random132loremasd23&quot; -H &quot;Content-Type: application/json&quot; -d '{&quot;name&quot;:&quot;ImportListSync&quot;}'\rНастройка и запуск крона на 5 мин #5_*_*_*_*.
crontab.guru/
yay -S cronie\rEDITOR=nano crontab -e\r5 * * * * curl -X POST &quot;http://localhost:6002/api/v3/command?apikey=6random132loremasd23&quot; -H &quot;Content-Type: application/json&quot; -d '{&quot;name&quot;:&quot;ImportListSync&quot;}'\rsudo systemctl enable --now cronie\rQbit jackett # Только поиск в qbittorrent youtu.be/DK-hcczVwq0.
mkdir ~/qbit\rcd ~/qbit\rnano docker-compose.yml\r---\rversion: &quot;2&quot;\rservices:\rqbittorrent:\rimage: linuxserver/qbittorrent\rcontainer_name: qbittorrent\renvironment:\r- PUID=1000\r- PGID=985\r- TZ=Europe/Moscow\r- UMASK_SET=022\r- WEBUI_PORT=6003\rvolumes:\r- ./qbittorrent:/config/qBittorrent\r- ./downloads:/downloads\rports:\r- 6881:6881\r- 6881:6881/udp\r- 6003:6003\rrestart: unless-stopped\rjackett:\rimage: linuxserver/jackett\rcontainer_name: jackett\renvironment:\r- PUID=1000\r- PGID=985\r- TZ=Europe/Moscow\rvolumes:\r- ./jackett:/config/Jackett\rports:\r- 6004:9117\rrestart: unless-stopped\rdocker compose up -d\rОпирался на следующие материалы # Тут немного про sonarr sprut.ai habr connect.smartliving.ru PSS:) Вопросы и предложения можно оставить в чате @ctlos.
Читайте также # Настройка Nginx и Docker Portainer — reverse proxy и управление контейнерами Настройка сервера Ubuntu 24.04 — Docker, Nginx, Dockge, UFW `}),e.add({id:9,href:"/posts/nginx-onion/",title:"Доступность веб сервера в tor и создание onion домена | Nginx tor onion",description:"Как запустить веб-сервер в Tor и создать onion-домен: настройка Nginx, генерация v3 ключей, reverse proxy и Onion-Location.",content:`Как запустить веб приложение и открыть доступность через tor в доменной зоне onion.
Video Все действия выполняются на Arch Linux, но суть везде одинакова, разница только в пакетном менеджере.
www.cloudflare.com/ Установка софта # Локально нужен только tor или tor браузер для доступа к будущему сервису, я буду использовать chromium с прокси портом тора 9050.
yay -S tor chromium\rНа сервере нужен tor и nginx.
yay -S tor nginx\rНастройка tor # Отредактировать конфиг на сервере /etc/tor/torrc, раскомментировать 2 строки.
sudo nano /etc/tor/torrc\rHiddenServiceDir /var/lib/tor/hidden_service/\rHiddenServicePort 80 127.0.0.1:80\rГенерация onion домена v3 # Генерировать не обязательно, по умолчанию tor сам создает нужные файлы в hidden_service при рестарте, но их можно удалить и создать имя с кастомным началом в hostname. Чем длиннее имя, тем дольше генерация.
github.com/cathugger/mkp224o git clone https://github.com/cathugger/mkp224o\rcd mkp224o\r./autogen.sh\r./configure\rmake\r# -t 2 потоки cpu, -n кол-во имен, имя topor\r./mkp224o topor -t 2 -v -n 1 -d ~/hs-keys\r#\rscp -r ~/hs-keys user@123.123.123.123:~/\rРекомендую сохранить ключи и hostname.
Права на hidden_service # На сервере после переноса файлов.
ssh user@123.123.123.123\rsudo cp -r ~/hs-keys/*/* /var/lib/tor/hidden_service/\rsudo chmod 700 /var/lib/tor/hidden_service\rsudo chown -R tor:tor /var/lib/tor/hidden_service/\rsudo systemctl restart tor\rsudo systemctl status tor\rsudo cat /var/lib/tor/hidden_service/hostname\rНастройка nginx # Важный момент, onion работает по http поэтому не нужно использовать редиректы на 443 порт https О первоначальной настройке nginx смотри тут.
Дефолтный конфиг /etc/nginx/nginx.conf, можно в секцию server добавить созданный onion домен и он будет выдавать содержимое по умолчанию из /usr/share/nginx/html, в данном случае index.hmtl.
# вырезка /etc/nginx/nginx.conf\rserver {\rlisten 80 default_server;\rlisten [::]:80 default_server;\rserver_name ctlos5lhe2vc3giixr.onion;\rroot /usr/share/nginx/html;\rindex index.htm index.html;\r...\rПростой конфиг, Nginx выводит содержимое директории.
sudo nano /etc/nginx/sites-available/onion.conf\rsudo ln -s /etc/nginx/sites-available/onion.conf /etc/nginx/sites-enabled\rserver {\r# директория со статикой сайта\rserver_name ctlos5lhe2vc3giixr.onion;\rroot /home/cretm/app/cloud.ctlos.ru;\rlisten 80;\rlisten [::]:80;\rlocation / {\rautoindex on;\rtry_files $uri $uri/ =404;\r}\r}\rПроверка и рестарт web сервера.
sudo nginx -t\rsudo systemctl restart nginx\rКонфиг с 2 доменами и ssl. С указанием Onion-Location, добавляет фиолетовый знак в тор браузере, сайт обязательно должен иметь ssl на основном домене.
sudo nano /etc/nginx/sites-enabled/onion.conf\rserver {\rserver_name dev.ctlos.ru;\rserver_name ctlos5lhe2vc3giixr.onion;\rroot /home/cretm/app/cloud.ctlos.ru;\rlisten 80;\rlisten [::]:80;\rlisten 443 ssl; # managed by Certbot\rssl_certificate /etc/letsencrypt/live/dev.ctlos.ru/fullchain.pem; # managed by Certbot\rssl_certificate_key /etc/letsencrypt/live/dev.ctlos.ru/privkey.pem; # managed by Certbot\rinclude /etc/letsencrypt/options-ssl-nginx.conf; # managed by Certbot\rssl_dhparam /etc/letsencrypt/ssl-dhparams.pem; # managed by Certbot\rlocation / {\rautoindex on;\rtry_files $uri $uri/ =404;\radd_header Onion-Location &quot;http://ctlos5lhe2vc3giixr.onion$request_uri&quot; always;\r}\r}\rРеверс прокси nginx. Пример направления домена на порт 5000 на котором работает не важно какой веб сервис, в данном случае Whoogle.
server {\rserver_name ctlos5lhe2vc3giixr.onion;\r# reverse proxy\rlocation / {\rproxy_pass http://localhost:5000; # Whoogle\rproxy_redirect off;\radd_header Onion-Location &quot;http://ctlos5lhe2vc3giixr.onion$request_uri&quot; always;\rproxy_set_header Host $http_host;\rproxy_set_header X-Real-IP $remote_addr;\rproxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\rproxy_set_header X-Forwarded-Proto $scheme;\rproxy_set_header Proxy &quot;Cloud-LB&quot;;\rproxy_set_header Upgrade $http_upgrade;\rproxy_pass_header Server;\rproxy_buffering off;\rproxy_http_version 1.1;\rtcp_nodelay on;\r}\r}\rВопросы и предложения можно оставить в чате @ctlos Читайте также # Tor проксирование в Arch Linux — настройка onion-трафика VPN сервер в Linux — WireGuard, SSH-туннель, Sshuttle Настройка Nginx и Docker Portainer — reverse proxy и контейнеры `}),e.add({id:10,href:"/posts/fluxbb-discourse/",title:"Перенос форума fluxbb на discourse",description:"Пошаговая инструкция по переносу форума FluxBB на Discourse: экспорт базы MySQL, импорт данных, настройка домена и обновление.",content:`Для переноса нужно получить базу данных форума fluxbb, наверняка вы знаете как это сделать, но если нет, то вот. Данные для подключение к базе, которые вы создавали, или то, что предоставил хостер, при создании.
host_ip - ip или домен mysql. user_db - имя пользователя базы PASS_WORD_DB - пароль к базе db_name - имя базы # получение через ssh\rssh creio@125.120.10.54 &quot;mysqldump -h host_ip -u user_db -pPASS_WORD_DB db_name&quot; &gt; ~/forum.sql\rLogin в docker # Копируем mysql дамп базы в докер контейнер и логинемся в него.
docker cp ~/forum.sql app:/var/www/discourse\r# docker exec -it app /bin/bash --login\rsudo ./launcher enter app\rУстановка mysql и запуск.
apt install -y mariadb-server mariadb-client libmariadb-dev\rservice mysql start\rСоздаем mysql базу, в которую выгрузим старые данные.
mysql -u root -p mysql\rmysql&gt; CREATE USER 'fluxbb'@'localhost' IDENTIFIED BY 'fluxbb';\rmysql&gt; CREATE DATABASE fluxbb;\rmysql&gt; GRANT ALL PRIVILEGES ON fluxbb.* TO 'fluxbb'@'localhost';\rmysql&gt; FLUSH PRIVILEGES;\rmysql&gt; exit\rЛогинимся под юзера discourse.
su discourse\rЭкспортируем базу данных fluxbb.
mysql -u fluxbb -p fluxbb &lt; forum.sql\r# pass\rfluxbb\rДобавляем зависимости в Gemfile.
echo &quot;gem 'mysql2'&quot; &gt;&gt; Gemfile\recho &quot;gem 'redcarpet'&quot; &gt;&gt; Gemfile\recho &quot;gem 'ruby-bbcode-to-md', git: 'https://github.com/nlalonde/ruby-bbcode-to-md'&quot; &gt;&gt; Gemfile\recho &quot;gem 'reverse_markdown'&quot; &gt;&gt; Gemfile\rУстановка зависимостей для корректной конвертации.
bundle config unset deployment\rbundle install --no-deployment --path vendor/bundle --jobs 4 --without test development\rДанные для подключение к mysql, возможно у вас нет FLUXBB_PREFIX в базе и будет ошибка, попробуйте убрать это значение.
FLUXBB_HOST=&quot;localhost&quot; FLUXBB_DB=&quot;fluxbb&quot; FLUXBB_USER=&quot;fluxbb&quot; FLUXBB_PW=&quot;fluxbb&quot; FLUXBB_PREFIX=&quot;bb_&quot; bundle exec ruby script/import_scripts/fluxbb.rb\rИзменение домена, полезно выполнить на тестовом домене, а когда все готово изменить на основной, meta.discourse.org.
Обновление discourse # Первым делом стоит обновить сам сервер(ubuntu/debian).
apt-get update\rapt-get dist-upgrade\rВключить автообновления(не обязательно) и не везде это возможно, для убунту.
sudo dpkg-reconfigure -plow unattended-upgrades\rDiscourse работает в докере и используются скрипты для упрощения.
sudo su\rcd /var/discourse\rgit pull\r./launcher rebuild app\rПосле обновления и запусков rebuild будут плодится контейнеры и images, которые забивают диск, но не используются.
# размер диска\rdf -h /\r# размеры директорий\rdu -sh /var/lib/*\rУдалить не нужные образы можно через docker, или через скрипт, имейте ввиду скрипт снесет все остановленные контейнеры и удалит все неиспользуемые образы. Дело в том, что если у вас работает, что-то еще кроме discourse в докере, то лучше работать именно самим docker-ом и удалять по id(7281bf55ce46).
# листинг контейнеров\rdocker ps -a\r# удаление контейнеров(CONTAINER ID)\rdocker rm 8ee579ceabf7\r# листинг образов\rdocker images\r# удаление образов(IMAGE ID)\rdocker rmi 7281bf55ce46\r# удаление всего скриптом\r./launcher cleanup\rОчистка системы apt.
apt-get autoclean\rapt-get autoremove\rЧитайте также # Настройка Nginx и Docker Portainer — reverse proxy и управление контейнерами `}),e.add({id:11,href:"/posts/web-server/",title:"Настройка и использование Nginx в Arch Linux | Docker Portainer",description:"Настройка Nginx reverse proxy в Arch Linux, проброс локальной сети через WireGuard, Docker Portainer для управления контейнерами.",content:`Nginx reverse proxy, проброс локальной сети на сервер, через wireguard. Portainer — gui для docker контейнеров.
Video
Nginx локально # Для установки на Arch.
sudo pacman -S nginx\rNginx docs ArchWiki Nginx Certbot Глобальный конфиг, при обращении по ip, nginx будет отдавать стандартную страницу, по пути /usr/share/nginx/html/index.html, некоторые настройки и импорты других конфигураций include, user - указываю юзера creio, от которого я работаю и из его директории в дальнейшем буду импортировать статичный сайт /media/files/github/ctlos/ctlos.github.io/_site, который сгенерирован jekyll, точнее это не его домашняя директория, но права на нее принадлежат ему.
sudo nano /etc/nginx/nginx.conf\ruser creio users;\rworker_processes 1;\r#error_log logs/error.log;\r#error_log logs/error.log notice;\r#error_log logs/error.log info;\r#pid logs/nginx.pid;\revents {\rworker_connections 1024;\r}\rhttp {\rinclude mime.types;\rdefault_type application/octet-stream;\r#access_log logs/access.log main;\rtypes_hash_max_size 4096;\rserver_names_hash_bucket_size 128;\rsendfile on;\r#tcp_nopush on;\rkeepalive_timeout 65;\rgzip on;\rserver {\rlisten 80 default_server;\rlisten [::]:80 default_server;\rroot /usr/share/nginx/html;\rindex index.htm index.html;\rserver_tokens off;\rautoindex off;\r}\rinclude sites-enabled/*;\r}\rСоздаем 2 директории в available будем складывать все конфиги сайтов, а в enabled будем создавать сим линки ln -s на то, что хотим включить, если нужно выключить, то просто удаляем конфиг(симлинк) из enabled. Файлы в этих директориях, как зеркала, не важно откуда мы их будем править.
sudo mkdir /etc/nginx/sites-{available,enabled}\rsudo nano /etc/nginx/sites-available/home.conf\rsudo ln -s /etc/nginx/sites-available/home.conf /etc/nginx/sites-enabled\r# если нужно удалить и не забудь перезапустить nginx\rsudo rm /etc/nginx/sites-enabled/home.conf\rКоманды nginx # Проверить конфигурацию на валидность.
sudo nginx -t\rЗапуск сервера, рестарт, стоп, средствами systemd.
sudo systemctl start nginx\rsudo systemctl restart nginx\rsudo systemctl stop nginx\rsudo systemctl status nginx\rДобавить в авто старт и убрать, если нужно.
sudo systemctl enable nginx\rsudo systemctl disable nginx\rПросмотр логов в зависимости, что указали в access_log и error_log.
cat /var/log/nginx/home.access\rЯ использую server_name домен, но можно манипулировать портами, если нет доменного имени, или воспользоваться freedns, no-ip и подобные. В конфиге ниже нет привязки к домену, а именно к порту, можно использовать и то и другое, как вместе, так и отдельно. В данном случае в браузере мы должны обратится ip:port ip:4000. Команда ip a покажет ip, обычно это 127.0.0.1(localhost), можно и так localhost:4000, www.duckdns.org/.
# cat /etc/nginx/sites-available/home.conf\rserver {\rlisten 4000;\rlisten [::]:4000;\r# server_name creio.duckdns.org;\rroot /media/files/github/ctlos/ctlos.github.io/_site;\rindex index.html index.htm index.php;\raccess_log /var/log/nginx/home.access;\rerror_log /var/log/nginx/home.error;\rlocation / {\rautoindex off;\rtry_files $uri $uri/ =404;\r}\rerror_page 404 /404.html;\rlocation = /404.html {\rinternal;\r}\rif ($request_uri = /index.html) {\rreturn 301 /;\r}\r}\rПример запуска jekyll, по умолчанию он стартует на localhost 127.0.0.1, порт 4000, но через vpn доступа к нему вы не получите, решение указать хост -H 0.0.0.0. В этом случае нам локально не нужен запущенный nginx, а сразу же настраиваем реверс на сервере. Jekyll используется для примера, тут может быть любое приложение на любом порту.
bundle exec jekyll serve -H 0.0.0.0\rКоманду можно повесить в авто запуск.
Nginx на сервере # Конфиг проброса (reverse proxy) локалки на сервер через vpn(wireguard), о его настройке я писал тут.
curl ident.me\rsudo systemctl start wg-quick@wg0\rip a\rВажный момент, если вы хотите иметь доступ к работающим докерам в локальной сети из вне, через vpn, находясь за nat с динамическим ip, обязательно используйте host сеть(0.0.0.0) &ndash;network host. При создании конфигурации в portainer, выбирайте сеть host для контейнера, или при ручном запуске контейнера указывайте(&ndash;network host). Просмотр сведений о сети. stackoverflow.com/q/32103885.
# iproute2\rss -tulpn\rПриложение работает и теперь можно настроить реверс прокси на сервере впн к этому порту, конфиг почти такой же как и в примере выше, только убираем путь root.
cat /etc/nginx/sites-enabled/home.ctlos.ru.conf\r# содержимое\rserver {\rlisten 80;\rlisten [::]:80;\rserver_name creio.duckdns.org;\raccess_log /var/log/nginx/home.access;\rerror_log /var/log/nginx/home.error;\r# reverse proxy\rlocation / {\rproxy_pass http://10.0.0.10:4000;\r# proxy_redirect http:// $scheme://;\rproxy_redirect off;\rproxy_buffering off;\rtcp_nodelay on;\rproxy_http_version 1.1;\rproxy_pass_header Server;\rproxy_set_header Host $http_host;\rproxy_set_header X-Real-IP $remote_addr;\rproxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\rproxy_set_header X-Forwarded-Proto $scheme;\rproxy_set_header Proxy &quot;Cloud-LB&quot;;\rproxy_set_header Upgrade $http_upgrade;\r}\r}\rВ proxy_pass http://10.0.0.10:4000; указываем ip wg клиента, то есть ваш локальный ip интерфейса wg, команда ip a покажет его. Рестарт nginx и посмотрим статус.
sudo systemctl restart nginx\rsudo systemctl status nginx\rПросмотр отдачи инфы сервером в vpn сети. Должно отдавать одни и теже данные, как локально, так и на сервере.
curl 10.0.0.10:4000\rТаким образом можно создать множество сайтов, пробросить нужные приложения в сеть из локальной сети, но обязательное условие, иметь сервер, иначе в этом мало смысла.
Docker Portainer # В данном подходе не обязательно иметь сервер и можно забыть о vpn, а организовать все локально, без всяких доступов за nat. Поднять в докерах plex, nextcloud и многое другое, а portainer позволяет легко этим управлять.
Установка Doker, docker-compose и настройка. wiki.archlinux.org/index.php/Docker.
sudo pacman -S docker-compose\rДобавляем пользователя от которого работаем(username) в группу docker.
sudo usermod -aG docker username\rВозможно стоит перезагрузиться. Включаем сервис и добавляем в авто-старт, если нужно.
sudo systemctl start docker\rsudo systemctl enable docker\rPortainer — веб интерфейс на 9000 порту, для управления docker контейнерами. documentation portainer. Создадим диск portainer_data, как сказано в доках.
docker volume create portainer_data\rОдна из команд ниже запустит portainer, о хост сети я уже говорил выше, но можно и использовать 2 команду, только необходимо немного ковырнуть докер. В случае отказа запуска сервиса docker, попробуйте. wiki.archlinux.org.
sudo systemctl daemon-reload\rsudo rm -rf /var/run/docker.sock\rsudo systemctl restart docker\rЕсли вы изменили socket, как сказано в вики, то используйте вторую команду, контейнер будет доступен в vpn сети на 9000 порту.
# запуск в host сети\rdocker run -d --network host --name=portainer --restart=always -v /var/run/docker.sock:/var/run/docker.sock -v portainer_data:/data portainer/portainer-ce --logo &quot;https://ctlos.github.io/assets/img/logo.svg&quot;\r# bridge ports, portainer-ce\rdocker run -d -p 9000:9000 --name=portainer --restart=always -v /var/run/docker.sock:/var/run/docker.sock -v portainer_data:/data portainer/portainer-ce --logo &quot;https://ctlos.github.io/assets/img/logo.svg&quot;\rКоманды docker # # список контейнеров\rdocker ps\r# остановка ID или Name\rdocker stop portainer\r# запуск ID или Name\rdocker start fc46d04d334d\r# удалить\rdocker rm portainer\r# удалить диск\rdocker volume rm portainer_data\rМногое можно делать в терминале, точнее все. Рекомендую детальней изучить docker-compose, docs.docker.com/.
Читайте также # Медиа-сервер в Docker — Radarr, Sonarr, Jackett, qBittorrent Настройка сервера Ubuntu 24.04 — Docker, Nginx, Dockge, UFW VPN сервер в Linux — проброс локальной сети через WireGuard `}),e.add({id:12,href:"/posts/oci/",title:"Установка Arch Linux в Oracle Cloud",description:"Установка Arch Linux в Oracle Cloud Free с нуля: bootstrap, btrfs, LVM, настройка SSH и загрузчика grub. Полное руководство с Console Connection.",content:` PS: У меня забанили аккаунт без предупреждения :).
Существует такое предложение от Oracle Cloud, можно получить 2 сервера в минимальной комплектации навсегда и первые 30 дней тестирования более широкого функционала, нужно привязать карту с которой спишут примерно 1 евро(мне вернули практически сразу) и телефон. Доступные дистрибутивы на free тарифе: ubuntu, centos, oracle linux oracle.com/cloud/free/.
После того, как я немного потрогал их кабинет задался целью развернуть у них Arch Linux, доступного образа у них нет, но я знаю о таком замечательном инструменте, как packer, все мои попытки запустить собранные packer-ом образы были не удачны. Образы практически на 100% уверен были в порядке, но я не знал как у них устроен efi загрузчик и не сообразил использовать Console Connection, об этом будет ниже www.packer.io/docs.
Для тех кому интересно, как залить туда custom image. В меню, Object storage - Bucket, создайте bucket, а в него загрузите образ. После этого в меню, Custom Images можно импортировать файл из бакета и уже из него создать Instance(машину).
Спустя примерно месяц я решил еще раз попробовать это провернуть, но доступ к функционалу Custom Images был закрыт, но я размотал его немного иначе.
Интерфейс, практически везде есть сноски на документацию, которую можно перевести и детальней узнать о работе. Собственно так я и знакомился с функционалом кабинета, методом тыка. На данный момент он мне даже кажется весьма удобным.
После создания машины(не важно какой), если в ней присутствует Файрвол, то открыть порты в нем мало, нужно еще открыть их в Default Security List. В меню, Networking - Virtual Cloud Networks - vcn-id - Security Lists - Default Security List vor vcn-id, иначе порты не будут доступны. Простыми словами их нужно открыть, как в Default Security List, так и на самой машине, при наличии Файрвола.
stackoverflow.com Генерация ключей # Локально создайте ssh ключи, если еще не сделали этого.
ssh-keygen -t rsa -b 4096 -C &quot;ctlos@protonmail.com&quot;\rКлючи упадут в ~/.ssh. При создании instance(машины), импортируйте публичный ключ id_rsa.pub.
Oracle Cloud # Создать минимальную машинку free, oracle linux 7.9, именно в ней будет swap раздел на 8G, который мы будем использовать для трансфера. Я не трогал настройки по умолчанию при создании. Авторизуемся на машине по ssh.
Arch bootstrap # Методы описаны в вики archlinux wiki.archlinux.org.
Копируем ссылку на bootstrap .tar.gz. Скачиваем и раскрываем архив в корень http://mirrors.evowise.com/.
# под root\rcd /\rwget http://mirrors.evowise.com/archlinux/iso/latest/archlinux-bootstrap-2021.03.01-x86_64.tar.gz\rtar xzf /archlinux-bootstrap-*-x86_64.tar.gz\rОтмонтировать swap он 8G, форматировать его в нужную фс(btrfs/ext4). В моем случае структура разделов.
/dev/sda1 boot, точка монтирования /boot/efi. /dev/sda2 swap(8G), его использую для трансфера. /dev/sda3 root(39G). На данный момент я тут с Oracle linux, в конце тут будет Arch с lts ядром. lsblk -f\rswapoff -a\rТеперь выполняем chroot в bootstrap, в нем выполняем дальнейшие действия. Его разворачиваем для доступа к pacstrap и arch-chroot, основная и единственная задача. Он сам смонтирует нужные бинды, но нужно еще выполнить pacman init и раскомментировать зеркала(первые 3 Worldwide Using_a_chroot_environment.
nano /root.x86_64/etc/pacman.d/mirrorlist\rls /\r/root.x86_64/bin/arch-chroot /root.x86_64\rpacman-key --init\rpacman-key --populate\rpacman -Syy\rМонтирование pacstrap # Форматируем, создаем нужные директории, снапшоты, монтируем. Обратите внимание boot я не форматирую, а просто перемонтирую и удалю из него загрузчик /boot/efi/EFI/redhat.
mkfs.btrfs -f -L &quot;root&quot; /dev/sda2\rmount /dev/sda2 /mnt\rbtrfs subvolume create /mnt/@\rbtrfs subvolume create /mnt/@home\rbtrfs subvolume create /mnt/@snapshots\rumount /mnt\rmount -o subvol=@,compress=lzo,relatime,space_cache,autodefrag /dev/sda2 /mnt\rmkdir -p /mnt/{boot/efi,home,snapshots}\rmount -o subvol=@home,compress=lzo,relatime,space_cache,autodefrag /dev/sda2 /mnt/home\rmount -o subvol=@snapshots,compress=lzo,relatime,space_cache,autodefrag /dev/sda2 /mnt/snapshots\rumount /dev/sda1\rmount /dev/sda1 /mnt/boot/efi\rРазворачиваем будущую систему с нужными пакетами, некоторые из них очень важны. Генерируем fstab и выполняем еще один chroot(да-да).
pacstrap /mnt base base-devel linux-lts linux-lts-headers btrfs-progs nano grub efibootmgr iproute2 iputils rng-tools open-iscsi arch-install-scripts pacman-contrib reflector openssh wget git rsync gnu-netcat pv unzip unrar p7zip zsh htop tmux psmisc procps-ng\rgenfstab -pU /mnt &gt;&gt; /mnt/etc/fstab\rarch-chroot /mnt\rInit pacman # Проинициализируем pacman, отсортируем зеркала и включаем mitilib репозиторий.
reflector -a 12 -l 30 -f 30 -p https,http --sort rate --save /etc/pacman.d/mirrorlist\rpacman-key --init\rpacman-key --populate\rsed -i &quot;/[multilib]/,/Include/&quot;'s/^#//' /etc/pacman.conf\rpacman -Syy --noconfirm\rДобавление пользователя # Назначим рут пароль, добавляем пользователя с нужными группами, включаем ему zsh. Назначаем пароль пользователю и включаем sudo.
usermod -p 123 root\ruseradd -m -g users -G &quot;log,network,storage,power,wheel&quot; -s /bin/zsh creio\rusermod -p 123 creio\recho &quot;%wheel ALL=(ALL) ALL&quot; &gt;&gt; /etc/sudoers\rСистемные настройки # Назначаем имя машины, часовой пояс, локали и русский шрифт в консоли.
echo cloud &gt; /etc/hostname\rln -svf /usr/share/zoneinfo/Europe/Moscow /etc/localtime\rhwclock --systohc --utc\recho &quot;en_US.UTF-8 UTF-8&quot; &gt; /etc/locale.gen\recho &quot;ru_RU.UTF-8 UTF-8&quot; &gt;&gt; /etc/locale.gen\rlocale-gen\recho &quot;LANG=ru_RU.UTF-8&quot; &gt; /etc/locale.conf\recho &quot;KEYMAP=ru&quot; &gt; /etc/vconsole.conf\recho &quot;FONT=cyr-sun16&quot; &gt;&gt; /etc/vconsole.conf\rMkinitcpio # Изменить строку HOOKS в файле /etc/mkinitcpio.conf, должно быть так. Важно! Не знаю почему, но с хуком udev отказывается стартовать init, поэтому обязательно замените его на systemd и удаляю fsck, так как btrfs.
HOOKS=(base systemd autodetect modconf block filesystems keyboard keymap)\rОбновить initramfs.
mkinitcpio -P\rЕсли проебали с хуком, то попадете в rootfs и можно принудительно назначить инит и включить его.
ln -s /lib/systemd/systemd /new_root/bin/init\rexec switch_root /new_root /bin/init\rСоздаем hosts # cat &lt;&lt;EOF &gt;/etc/hosts\r127.0.0.1 localhost\r::1 localhost\r127.0.1.1 cloud.localdomain cloud\rEOF\rВключаем интернет # cat &lt;&lt;EOF &gt;/etc/systemd/network/20-ethernet.network\r[Match]\rName=en*\rName=eth*\r[Network]\rDHCP=yes\rEOF\rsystemctl enable systemd-networkd\rsystemctl enable systemd-resolved\r# Workaround for https://bugs.archlinux.org/task/58355\rsystemctl enable rngd\rУстанавливаем grub # grub-install --target=x86_64-efi --efi-directory=/boot/efi\rGrub.cfg приводим к такому виду, все остальное закомментировано(#)
nano /etc/default/grub\rGRUB_DEFAULT=0\rGRUB_TIMEOUT=0\rGRUB_DISTRIBUTOR=&quot;Arch&quot;\rGRUB_CMDLINE_LINUX_DEFAULT=&quot;console=tty1 console=ttyS0 nvme.shutdown_timeout=10 libiscsi.debug_libiscsi_eh=1 quiet&quot;\rGRUB_CMDLINE_LINUX=&quot;&quot;\rGRUB_PRELOAD_MODULES=&quot;part_gpt part_msdos&quot;\rГенерируем конфиг grub.
grub-mkconfig -o /boot/grub/grub.cfg\rУдаляем дефолт загрузчик.
rm -rf /mnt/boot/efi/EFI/redhat\rТак как мы снесли дефолтный загрузчик, нужно подсунуть нужный файл efi для автоматической загрузки.
echo &quot;EFIarchgrubx64.efi&quot; &gt; /boot/efi/startup.nsh\rSsh # Раскомментируем строки и приведем их к такому виду.
nano /etc/ssh/sshd_config\rPermitRootLogin yes\rPubkeyAuthentication yes\rPasswordAuthentication yes\rUseDNS no\rВключаем сервис.
systemctl enable sshd\rВыходим из chroot раздела(sda2) exit. Отмантируем разделы.
umount -R /mnt\rИ еще раз exit выходим из archlinux-bootstrap(/root.x86_64).
Следующий шаг важен, он мне сильно помог в отладке, так как доступ получаем выше самой машины, очень удобно.
Перейдите в нужный instance и создайте на вкладке Console Connection подключение ssh, импортируйте открытый ключid_rsa.pub. После активации подключения в меню(3 точки справа) скопируйте Copy Serial Console Connection for Linux/Mac данные, вставьте данные из буфера в новый терминал.
ssh -o ProxyCommand='ssh -W %h:%p -p 443 ocid1.instnection.oc1.eu-frankfurt-1.antheljtuhavnyqwertyrey@instance-console.eu-frankfurt-1.oraclecloud.com' ocid1.instance.oc1.eu-frankfurt-1.qwretfhjczsdfetrydfgdfsfd\r# прожать Enter\rВ исходном терминале, перезагружаем машину.
systemctl reboot\rВ терминале с ssh -o ProxyCommand должны увидеть efi меню, которое выполнит скрипт /boot/efi/startup.nsh(5 секунд) и запустит grub, grub не увидим, так как он выставлен в 0.
Efishell # Если что-то выполнили не так увидите efishell&gt;, некоторые команды.
# карта\rmap\r# меню\rbcfg boot dump\r# переход в раздел\rFS0:\r# посмотреть созданный efi файл\rls EFIarch\r# запустить\rEFIarchgrubx64.efi\r# выход в псевдографику\rexit\r# добавляет пунк, работает до ребута\rbcfg boot add 0 FS0:EFIarchgrubx64.efi &quot;Arch lts&quot;\rИменно по причине того, что загрузчик слетает и используется /boot/efi/startup.nsh, именно поэтому и не стартовал мой custom image о котором я говорил в начале.
Авторизация # Если все нормально, копируем ключ в root-а и юзера, в моем случае creio.
cat .ssh/id_rsa.pub | ssh root@192.168.1.35 'mkdir -p ~/.ssh &amp;&amp; cat &gt;&gt; .ssh/authorized_keys'\rcat .ssh/id_rsa.pub | ssh creio@192.168.1.35 'mkdir -p ~/.ssh &amp;&amp; cat &gt;&gt; .ssh/authorized_keys'\rВыполняем вход.
ssh creio@192.168.1.35\rДолжны увидеть меню zsh, нажать 0.
Перенос # Форматируем и монтируем sda3. Создаем снапшоты.
lsblk -f\rmkfs.btrfs -f -L &quot;root&quot; /dev/sda3\rmount /dev/sda3 /mnt\rbtrfs subvolume create /mnt/@\rbtrfs subvolume create /mnt/@home\rbtrfs subvolume create /mnt/@snapshots\rumount /mnt\rmount -o subvol=@,compress=lzo,relatime,space_cache,autodefrag /dev/sda3 /mnt\rmkdir -p /mnt/{boot/efi,home,snapshots}\rmount -o subvol=@home,compress=lzo,relatime,space_cache,autodefrag /dev/sda3 /mnt/home\rmount -o subvol=@snapshots,compress=lzo,relatime,space_cache,autodefrag /dev/sda3 /mnt/snapshots\rumount /dev/sda1\rmount /dev/sda1 /mnt/boot/efi\rКопируем текущий корень в /mnt.
rsync -cauv --info=stats2 --exclude={&quot;/dev/*&quot;,&quot;/proc/*&quot;,&quot;/sys/*&quot;,&quot;/tmp/*&quot;,&quot;/run/*&quot;,&quot;/mnt/*&quot;,&quot;/media/*&quot;,&quot;/lost+found&quot;,&quot;/var/lib/pacman/sync/*&quot;,&quot;/var/cache/*&quot;,&quot;/var/tmp/*&quot;} /* /mnt/\rFstab # Узнаем UUID разделов.
lsblk -f\rИзменить fstab, nano /mnt/etc/fstab. Загрузчик не изменился, только UUID субволумов.
# /dev/sda1\rUUID=2138-EC84 /boot/efi vfat defaults 0 0\r# /dev/sda3\rUUID=39b2a28d-3890-425b-8152-fed18a73fdcd / btrfs subvol=@,defaults,noatime,space_cache,autodefrag 0 0\r# /dev/sda3\rUUID=39b2a28d-3890-425b-8152-fed18a73fdcd /home btrfs subvol=@home,defaults,noatime,space_cache,autodefrag 0 0\r# /dev/sda3\rUUID=39b2a28d-3890-425b-8152-fed18a73fdcd /snapshots btrfs subvol=@snapshots,defaults,noatime,space_cache,autodefrag 0 0\rChroot # arch-chroot /mnt\rПереустановим и сконфигурируем grub.
grub-install --target=x86_64-efi --efi-directory=/boot/efi\rgrub-mkconfig -o /boot/grub/grub.cfg\rПосмотрим на правильность UUID. Везде должен быть id sda3.
cat /boot/grub/grub.cfg\rlsblk -f\rВыходим из chroot, отмонтируем, ребут.
exit\rumount -R /mnt\rsystemctl reboot\rОпять, можем запустить ssh -o ProxyCommand(прожать Enter) и наблюдать за работой efi, если все ровно, выполняем вход. Теперь можно отформатировать sda2 в swap и подключить его в fstab.
mkswap /dev/sda2\rswapon /dev/sda2\rswapon --show\rlsblk -f\rnano /etc/fstab\r# добавить в конец с новой строки\r# /dev/sda2\rUUID=6a1059e2-6fd0-4894-bb14-53ff59754145 none swap defaults 0 0\rДополнительный диск # Отредактируйте файл /etc/iscsi/iscsid.conf, как указано в help iscsiinformation.htm. На вкладке boot volumes можно создать дополнительный диск, клонировать существующий. После этого добавить на машине в автостарт и запустить сервис.
sudo systemctl enable --now iscsid\r# включаем авторизацию\rsudo systemctl enable iscsi\rЗайти в свой Instances и в левом меню на вкладку Attached Block Volumes, присоединить клонированный диск, когда он перейдет в состояние Attached в правом меню открыть пункт iSCSI Commands &amp; Information. Скопировать 3 команды(iscsiadm) на подключение и выполнить их на своей машине(по строчно) от пользователя.
В поле ниже, соответственно команды на отключение.
lsblk -f\rФорматируем данный диск на свое усмотрение и прописываем, если нужно в fstab.
# создаем таблицу и раздел/разделы\rsudo cfdisk -z /dev/sdb\rЯ выбрал gpt, затем создал раздел по умолчанию на все пространство(46,6G), enter - enter - enter, курсор вправо(записать) - yes - enter, курсор влево(выход). Форматируем в ext4 с меткой files.
sudo mkfs.ext4 /dev/sdb1 -L files\rДобавляю в fstab.
sudo mkdir -p /media/files\rlsblk -f\rsudo nano /etc/fstab\r# /dev/sdb1\rUUID=702c830e-efb9-403d-bdfc-b3a969d44b1f /media/files ext4 defaults,_netdev,x-systemd.requires=iscsid.service 0 1\rПерезагружаюсь и вижу по пути /media/files чистый раздел, под любые нужды.
sudo systemctl reboot\rДадим полные права в директорию для юзера.
sudo chown -R $(whoami):users /media/files\rВы наверно догадались, что можно было сразу подключить второй диск и развернуть на него, тем самым опустить момент с переносом раздела(rsync), я это специально сделал, чтобы показать больше.
Рекомендации # Уменьшение журнала Systemd # sudo nano /etc/systemd/journald.conf\rРаскомментировать и изменить строку.
SystemMaxUse=100M\rПерезапустите сервис.
sudo systemctl restart systemd-journald.service\rУвеличить /tmp # df -h /tmp\rsudo mount -o remount,size=2G /tmp\rKexec # Это полезно при обновлении ядра, можно очень быстро перезагрузить его, не дожидаясь завершения всего процесса загрузки BIOS. Наглядно видно, при доступном обновление ядра wiki.archlinux.org/index.php/Kexec.
yay -S kexec-tools\r# версия ядра\runame -a\r# полное обновление\ryay -Syyuu\r# загрузка нового ядра\rsudo kexec -l /boot/vmlinuz-linux-lts --initrd=/boot/initramfs-linux-lts.img --reuse-cmdline\r# частичный ребут\rsudo systemctl kexec\r# справка\rsudo kexec -h\rSwapfile # Можно отключить раздел swap и использовать файл на 4G в btrfs.
truncate -s 0 /swapfile\rchattr +C /swapfile\rbtrfs property set /swapfile compression none\rfallocate /swapfile -l4g\rchmod 600 /swapfile\rmkswap /swapfile\rlsattr /swapfile\rswapon /swapfile\rЗакомментировать раздел swap и добавить строку с файлом.
sudo nano /etc/fstab\r/swapfile none swap defaults 0 0\rСсылки # Еще некоторые конфиги и скрипты в моем репозитории Итог # Таким способом можно переделать любую систему и практически на любом облачном решении, главное знать детали загрузки и хорошо бы иметь ssh подключение выше, как тут (Console connection), или некий режим восстановления.
Вступай в чат @ctlos Всем Добра.
Читайте также # Настройка zsh Установка Arch Linux на LVM на LUKS — шифрование диска при установке VPN сервер в Linux — настройка WireGuard `}),e.add({id:13,href:"/posts/vpn/",title:"Как Создать и Настроить VPN сервер в Linux | Wireguard",description:"Как создать VPN-сервер в Linux с помощью WireGuard, SSH-туннеля и Sshuttle. Пошаговая инструкция по настройке сервера и клиента.",content:`Речь пойдет о шифровании трафика в сети и обходе блокировок, рассмотрю несколько способов.
Video
Всё реализовано в дроплете Digital Ocean
Psiphon о котором я уже упоминал в прошлом посте
Ssh туннель через сервер в tor
Sshuttle прокси
Wireguard
Гуляем по сети, как рыбы в океане :).
Ssh туннель # Установить ssh.
yay -S openssh\rДопустим на вашем сервере запущен tor или прокси, через ssh легко можно пробросить порт на котором это работает. Про настройку ssh я писал в ctlos wiki.
Ctlos wiki ssh OpenSSH Tor Установить tor.
yay -S tor torsocks\rssh -L 9050:127.0.0.1:9050 -p 22 cretm@134.122.88.241 -N\r127.0.0.1(localhost) — локальный адрес. Первый 9050, локальный порт. Второй 9050, на сервере. -N говорит не открывать соединение, а только проброс. Теперь локально доступен 9050 и можно открыть на нем chromium в другом терминале.
chromium --proxy-server='socks://127.0.0.1:9050'\rИли посмотреть ip через torify, или запустить шелл и выполнять все через tor.
torify curl ident.me\r# или\rtorify zsh\rSshuttle # Позволяет завернуть весь трафик через ssh сервер.
repo Статейка habr И еще одна Установка.
yay -S sshuttle\rЗапуск.
sshuttle --dns -r cretm@134.122.88.241 -x 134.122.88.241 0/0\rWireguard # Я все проделываю скриптом easy-wg-quick.
Arch Wiki wireguard easy-wg-quick wireguard quickstart Сервер # yay -S wireguard-tools gawk grep iproute2 net-tools qrencode wget\r# если ядро lts\ryay -S wireguard-lts\rmkdir vpn &amp;&amp; cd vpn\rwget -O vpn.sh https://raw.githubusercontent.com/burghardt/easy-wg-quick/master/easy-wg-quick\rchmod +x vpn.sh\rВыполните reboot после установки.
Можно задать конкретный порт и ip. Узнать.
Если за nat curl ident.me Нет nat ip a Путем отправки данных в файлы.
curl ident.me &gt; extnetip.txt\r# или\recho 134.122.88.241 &gt; extnetip.txt\recho 51820 &gt; portno.txt\rСоздание конфигурации и клиента.
./vpn.sh comp\rЗапуск, остановка, статус работы.
sudo wg-quick up ./wghub.conf\rsudo wg-quick down ./wghub.conf\rsudo wg show\rОткрыть порт если установлен файрвол, рестарт и просмотр статуса.
sudo ufw allow 51820/udp\rsudo ufw reload\rsudo ufw status\rnetstat -tulpn\rЕсли на сервере iptables.
sudo iptables --policy INPUT ACCEPT\rsudo iptables -F\rsudo iptables -A INPUT -p tcp --dport 22 -m state --state NEW -j ACCEPT\rsudo iptables -A INPUT -p udp --dport 51820 -m state --state NEW -j ACCEPT\rsudo netfilter-persistent save\rУдалить правило, где 5 линия. В данном случае удалять ничего не нужно, просто знайте, как работает удаление.
sudo iptables --list --line-numbers\rsudo iptables -D INPUT 5\rsudo netfilter-persistent save\rСоздаем второго клиента для мобилки. Сканируем qr в приложении wireguard и перезапускаем сервер.
./vpn.sh mob\rsudo wg-quick down ./wghub.conf\rsudo wg-quick up ./wghub.conf\rsudo wg show\rВывод qr кода.
qrencode -t ansiutf8 &lt; wgclient_mob.conf\rОсновной конфиг с инфой о клиентах.
cat wghub.conf\rМожно добавить в автостарт systemd.
sudo cp wghub.conf /etc/wireguard/wghub.conf\rsudo systemctl enable --now wg-quick@wghub\rsystemctl status wg-quick@wghub\rКлиент # Для клиента Arch Linux. Настройка на вашем компе.
yay -S wireguard-tools\rsudo nano /etc/wireguard/wg0.conf\rСкопировать с сервера содержимое файла wgclient_comp.conf, пример.
# 10: comp &gt; wgclient_comp.conf\r[Interface]\rAddress = 10.256.112.10/24, fd51:9999:3322:6414::10/64\rDNS = 1.1.1.1, 2606:4700:4700::1111\rPrivateKey = UGdsdfgsdgdfgiJRhlQdX7kQ=\r[Peer]\rPublicKey = wvr/gmg/FJN0dfgdfhdfhudRLdIdn+2DQ=\rPresharedKey = /DXNfgNi2iMY5jrdgdfgdgu5tyIX94Xvss=\rAllowedIPs = 0.0.0.0/0, ::/0\rEndpoint = 134.111.10.21:51820\rPersistentKeepalive = 25\rВключить сервис systemd и добавить в автостарт если нужно.
sudo systemctl start wg-quick@wg0\rsudo systemctl enable wg-quick@wg0\rsudo systemctl enable --now systemd-resolved\rИмейте ввиду если на сервере, что-то не так, то и у вас не будет интернета при включенном сервисе. Остановить, выключить.
sudo systemctl stop wg-quick@wg0\rsudo systemctl disable wg-quick@wg0\rПроверить ip можно на 2ip.ru, в терминале.
curl ident.me\rПроверить скорость интернета.
curl -s https://raw.githubusercontent.com/sivel/speedtest-cli/master/speedtest.py | python -\rЧитайте также # Tor проксирование в Arch Linux — настройка доступа к .onion сайтам WireGuard + Pi-hole + Unbound — приватный DNS без утечек Nginx onion: веб-сервер в Tor — создание onion-домена `}),e.add({id:14,href:"/posts/",title:"Blog posts",description:"Практические инструкции, статьи и кейсы по AI-автоматизации, администрированию Linux и веб-разработке от автора Ctlos Linux. Понятно, по делу и без воды.",content:""}),e.add({id:15,href:"/posts/psiphon/",title:"Psiphon linux, обходим блокировку трафика",description:"Обход блокировок сайтов в Linux с помощью Psiphon. Установка, настройка прокси в браузере и Telegram.",content:`Psiphon — бесплатный инструмент для обхода блокировок сайтов. Работает через прокси-серверы, не требует настройки VPN. Устанавливается из AUR и сразу готов к работе.
Archlinux # В aur лежит пакет.
brainfuck-psiphon-pro-go Репо проекта Установка # yay -S brainfuck-psiphon-pro-go-bin\rИспользование # Запуск командой sudo brainfuck-psiphon-pro-go. Увидите примерно такой вывод.
Brainfuck Tunnel [Psiphon Pro Go Version. 1.3.210109]\r(c) 2020 Aztec Rabbit.\r[17:15:55] :: INFO :: Domain Fronting running on port 8989\r[17:15:55] :: INFO :: Proxy Rotator running on port 3080\r[17:15:55] :: 3081 :: Connecting\r[17:15:55] :: 3082 :: Connecting\r[17:15:55] :: 3084 :: Connecting\r[17:15:55] :: 3083 :: Connecting\r[17:16:08] :: 3083 :: Connected\r[17:16:09] :: 3082 :: Connected\r[17:16:09] :: 3081 :: Connected\r[17:16:10] :: 3084 :: Connected\rМожно запустить с использованием региона (us,nl,sg).
sudo brainfuck-psiphon-pro-go -r nl\rПрописываем прокси в браузере, или в telegram. Прокси ратируются на портах 3080-3084 в моем случае, наверняка у вас также.
http proxy: 127.0.0.1 port 3080\rhttps proxy: 127.0.0.1 port 3080\rftp proxy: 127.0.0.1 port 3080\rsocks: 127.0.0.1 port 3080\rChromium можно запустить с флагом.
chromium --proxy-server='socks://127.0.0.1:3080'\rВ firefox используйте расширение FoxyProxy, или в параметрах сети укажите только SOCKS5.
В настройках расширения, Добавить новый SOCKS5, ip: 127.0.0.1, port: 3080
Конфигурация # Можно изменить ProxyRotator порт, если нужно.
# nano ~/.config/brainfuck-psiphon-pro-go/config.json\r{\r&quot;ProxyRotator&quot;: {\r&quot;Port&quot;: &quot;3080&quot;\r},\r&quot;Inject&quot;: {\r&quot;Enable&quot;: true,\r&quot;Type&quot;: 2,\rHelp.
sudo brainfuck-psiphon-pro-go -h\rЧитайте также # Tor проксирование в Arch Linux — настройка доступа к .onion сайтам VPN сервер в Linux — WireGuard, SSH-туннель, Sshuttle `}),e.add({id:16,href:"/posts/arch-lvm-luks/",title:"Установка Arch Linux на зашифрованный раздел, LVM на LUKS",description:"Установка Arch Linux на зашифрованный раздел LVM на LUKS: шифрование диска, настройка grub, резервное копирование заголовка.",content:`Грузимся из под live-usb, устанавливаем ru язык и время.
loadkeys ru\rsetfont cyr-sun16\rtimedatectl set-ntp true\rПодготовка к установке # Создаем таблицу на диске MBR(DOS) и 2 первичных раздела.
LUKS под root, swap, home boot 512M, выставляем флаг boot cfdisk\rШифруем, открываем раздел. Создаем контейнер.
# подтверждаем YES\rcryptsetup -y luksFormat --type luks2 /dev/sda1\rcryptsetup open /dev/sda1 cryptlvm\rpvcreate /dev/mapper/cryptlvm\rvgcreate lvarch /dev/mapper/cryptlvm\rls -l /dev/mapper/cryptlvm\rСоздаём разделы lvm.
lvcreate -L 4G -n swap lvarch\rlvcreate -L 25G -n root lvarch\rlvcreate -l 100%FREE -n home lvarch\rФорматируем и включаем swap.
mkfs.ext2 -L boot /dev/sda2\rmkfs.ext4 -L root /dev/lvarch/root\rmkfs.ext4 -L home /dev/lvarch/home\rmkswap -L swap /dev/lvarch/swap\rswapon /dev/lvarch/swap\rМонтируем и создаем директории.
mount /dev/lvarch/root /mnt\rmkdir /mnt/{home,boot}\rmount /dev/lvarch/home /mnt/home\rmount /dev/sda2 /mnt/boot\rУстановка и настройка # Установка базовой системы и необходимых пакетов.
pacstrap /mnt base base-devel linux linux-headers linux-firmware lvm2 nano networkmanager bash-completion reflector htop openssh curl wget git rsync unzip unrar p7zip gnu-netcat pv\rГенерируем и правим, если нужно fstab, выполняем chroot.
genfstab -pU /mnt &gt;&gt; /mnt/etc/fstab\rcat /mnt/etc/fstab\rarch-chroot /mnt\rВключаем multilib и сортируем зеркала.
sed -i &quot;/[multilib]/,/Include/&quot;'s/^#//' /etc/pacman.conf\rreflector -c &quot;Russia&quot; -c &quot;Belarus&quot; -c &quot;Ukraine&quot; -c &quot;Poland&quot; -f 20 -l 20 -p https -p http -n 20 --save /etc/pacman.d/mirrorlist --sort rate\rПароль root.
passwd\rСоздаем пользователя st в нужных группах, назначаем пароль и включаем sudo.
useradd -m -g users -G &quot;adm,audio,log,network,rfkill,scanner,storage,optical,power,wheel&quot; -s /bin/bash -c &quot;Alex Creio&quot; st\rpasswd st\recho &quot;%wheel ALL=(ALL) ALL&quot; &gt;&gt; /etc/sudoers\rНазначаем hostname: имя машины и часовой пояс, время.
echo &quot;ctlos&quot; &gt; /etc/hostname\rln -svf /usr/share/zoneinfo/Europe/Moscow /etc/localtime\rtimedatectl set-ntp true\rГенерируем локали и включаем русский язык системы.
echo &quot;en_US.UTF-8 UTF-8&quot; &gt; /etc/locale.gen\recho &quot;ru_RU.UTF-8 UTF-8&quot; &gt;&gt; /etc/locale.gen\rlocale-gen\recho &quot;LANG=ru_RU.UTF-8&quot; &gt; /etc/locale.conf\rДобавляем поддержку ru в консоле.
echo &quot;KEYMAP=ru&quot; &gt;&gt; /etc/vconsole.conf\recho &quot;FONT=cyr-sun16&quot; &gt;&gt; /etc/vconsole.conf\rДобавляем хуки (порядок важен) и создаем загрузочный образ.
### добавить keyboard keymap encrypt lvm2\r# HOOKS=(base udev autodetect keyboard keymap modconf block encrypt lvm2 filesystems fsck)\rnano /etc/mkinitcpio.conf\rmkinitcpio -p linux\rУстанавливаем Grub.
pacman -S --noconfirm --needed grub\rgrub-install /dev/sda\rНастраиваем и конфигурируем grub.
## узнаём UUID\rblkid /dev/sda1\r# /dev/sda1: UUID=&quot;c0868972-f314-48e1-9be5-3584826dbd64&quot; TYPE=&quot;crypto_LUKS&quot; PARTUUID=&quot;bbb93e39-01&quot;\rnano /etc/default/grub\r## Прописываем команду для старта и включаем.\rGRUB_CMDLINE_LINUX=&quot;cryptdevice=UUID=c0868972-f314-48e1-9be5-3584826dbd64:cryptlvm root=/dev/lvarch/root&quot;\rGRUB_ENABLE_CRYPTODISK=y\r## конфигурируем\rgrub-mkconfig -o /boot/grub/grub.cfg\rВключаем необходимые сервисы.
systemctl enable NetworkManager\rsystemctl enable sshd\rВыходим из chroot, отмонтируем разделы и закроем контейнер.
exit\rumount -Rf /mnt\rvgchange -a n lvarch\rcryptsetup close cryptlvm\rРезервное копирование luksHeader # Просмотр информации.
cryptsetup luksDump /dev/sda1\rОбязательно создайте backup заголовка.
cryptsetup luksHeaderBackup /dev/sda1 --header-backup-file luksheader.bac\rШифруем.
openssl enc -aes-256-cbc -salt -in luksheader.bac -out luksheader.bac.enc\rrm luksheader.bac\rРасшифровываем.
openssl enc -d -aes-256-cbc -in luksheader.bac.enc -out luksheader.bac\rВосстанавливаем, подтверждаем: YES.
cryptsetup luksHeaderRestore --header-backup-file luksheader.bac /dev/sda1\rСохраняем в надёжное место luksheader.bac.enc, например на usb. Стеганографируем и в публичный доступ (video).
Profit!
`}),e.add({id:17,href:"/posts/bspwm-0-1/",title:"Ctlos Linux Bspwm v0.1.0",description:"Весьма не плохой оконный менеджер",content:`Создано в рамках Ctlos Linux, demo Video.
Оформление # Тема gtk: модификация Arc-Dark. Иконки: Arc, dui-ico. Курсор: capitaine-cursors. Шрифт: Clear Sans Medium,9 ttf-clear-sans. Шрифт терминала: Hack Nerd Font Mono,9 ttf-nerd-fonts-hack-complete-git. Панели # Верхний бар: polybar # Элементы:
Запуск меню: левый клик - rofi, правый клик - jgmenu. Urxvt с сессией tmux. Сессия сохраняется, при закрытии и восстанавливается, при следующем нажатии. Newsboat - rss читалка. Монитор cpu и ram. Доступные обновления, клик: pacui - псевдо графический менеджер пакетов. Рабочие столы (теги). Сервис tor. Включить левый клик, выключить правый. Music контроллер. Звук по скроллу, клик - выкл. Дата. Лклик - подробней, Пклик - календарь. Раскладка. Меню выхода. Нижний бар: tint2(трэй) # Key Description udiskie монтирование usb. redshift-gtk цветовой тон экраа. xfce4-power-manager менеджер питания. clipit менеджер буфера обмена. ctrl+alt+h открыть историю. Горячие клавиши # Многое переопределено, никто не мешает использовать дефолт, sxhkdrc.
Режимы и управление окнами # Режим тайлинга tiled, плитка. Режим pseudo_tiled, псевдо тайлинг. Нечто среднее между floating и tiled. Режим floating, плавающий режим. Режим fullscreen, Весь экран. Режим monocle, окно занимает всё доступное пространство. Зажатая Super(win) и клавиши мыши манипулируют окнами: размер, положение.
Key Description super + a Псевдо тайлинг. super + s floating, плавающий режим. super + d тайлинг. super + f fullscreen. super + m Переключение режима monocle. alt + space Переключение режима тайлинг/floating. super + g Приклеить окно. super + z Закрыть окно. super + - Скрыть/показать окно. super + c Переход в режим monocle, отключение рамок и отступов. super + v Отключение отступов. super + {↑,↓} Уменьшение/увеличение отступов, super + c в исходное состояние. super + scroll Уменьшение/увеличение отступов, super + c в исходное состояние. super + {←,→,↑,↓} Перемещение окна в режиме floating. super + {h,j,k,l} перемещение по окнам в режиме tiled. super + alt + {h,j,k,l} изменение размера в режиме tiled. super + shift + {h,j,k,l} перетаскивание в режиме tiled. alt + tab Переключение окна на текущем теге. super + tab Переключение на предыдущий тег. super + {1-9,0} Переход на тег. super + {q&hellip;o,0} Переход на тег. super + alt + {←,→} Перемещение по тегам. super + alt + {1-9,0} Отправка окна на номер тега. super + ctrl + p Скрыть/показать polybar. Запуск утилит # Key Description alt + shift Переключение раскладки. super + alt + r Рестарт bspwm. super + alt + q Выход из bspwm. super + Escape Релоад конфига горячих клавиш sxhkd. alt + Return Терминал драйвинг, задаем координаты старта, зажатым ЛКМ. super + Return Терминал на первом теге, в режиме тайлинга, monocle. alt + t Терминал в режиме floating. alt + r Ranger - консольный менеджер файлов. alt + d Rofi - меню. alt + w Firefox. alt + f Thunar. super + Delete Блокировка экрана. super + alt + Delete Меню выхода. Print скрин с отправкой в ~/Pictures/screen(директория должна быть). Копируется в буфер. super + Print скрин в режиме выделения. super + alt + Print скрин с задержкой 5 сек. и отправкой в ~/Pictures/screen(директория должна быть). Копируется в буфер. super + alt + m Текущий трек в ncmpcpp. ctrl + alt + {c,v} Копировать/вставить в терминале. Конфигурационные файлы # Key Description ~/.config/bspwm/bspwmrc Основной конфиг. ~/.config/bspwm Скрипты. /usr/bin/bspwm_start Скрипт автостарта, редактировать от ROOT. Он вызывается в ~/.xinitrc и в SDDM /usr/share/xsessions/bspwm.desktop. ~/.config/sxhkd/sxhkdrc Конфиг горячих клавиш. /etc/sddm.conf Конфиг менеджера входа SDDM. ~/.config/bspwm/polybar Скрипты и конфиг polybar. ~/.config/tint2/tray.tint2rc Конфиг tint2 трей. В меню есть gui-конфигуратор (Настройки tint). ~/.config/picom.conf Декоратор окон, композитный менеджер. ~/.Xresources Конфиг Urxvt терминала. После изменения файла выполнить xrdb -merge $HOME/.Xresources. ~/.colors Палитры терминала, указывать в ~/.Xresources строка #include &quot;.colors/sn&quot;. ~/.zshrc Конфиг оболочки $SHELL. ~/.alias_zsh Алиасы и функции zsh, сокращения команд терминала. Это основа, все остальное в ~/ и ~/.config.
Утилиты # Key Description lxappearance, qt5ct настройка внешнего вида. lxrandr разрешение экрана. ranger, thunar файловые менеджеры. fzf инкрементальный поиск, zz. micro консольный текстовый редактор, привычные клавиши:) ctrl+s - сохранить, ctrl+q - выход и т.д. mousepad Gui текстовый редактор. ncmpcpp, audacious музыкальный плеер. youtube-dl, youtube-viewer, streamlink скачивание, просмотр, просмотр стриминга. xreader просмотр pdf. viewnior просмотр изображений. mpv видео плеер. keepassxc менеджер паролей. veracrypt шифрование файлов. pavucontrol управление звуком. file-roller менеджер архивов. timeshift резервное копирование. flameshot скриншоты. simplescreenrecorder Запись экрана. tmux терминальный мультиплексор. rxrun.sh Tmux с 3 табами. ~/.bin/rxrun.sh. gufw межсетевой экран. cava визуализатор. gotop Консольный системный монитор. neofetch, fetch, pfetch информация о системе. ~/.bin/fetch. Еще некоторые скрипты: ~/.bin. Полный список пакетов: packages.both. Вступай в telegram чат: t.me/ctlos. Читайте также # Настройка Zsh — oh-my-zsh, плагины, конфигурация Настройка терминала Urxvt — шрифты, цвета, плагины `}),e.add({id:18,href:"/posts/zsh-config/",title:"Zsh Config",description:"Настройка Zsh в Arch Linux: установка oh-my-zsh, плагины fast-syntax-highlighting и zsh-autosuggestions, конфигурация ~/.zshrc.",content:`Разбор конфига ~/.zshrc, конечный результат примерно такой. Рекомендую установить и использовать терминал urxvt о настройке которого я писал в прошлом посте.
Установка пакетов # yay -S zsh oh-my-zsh fast-syntax-highlighting zsh-autosuggestions\roh-my-zsh: надстройка над zsh. fast-syntax-highlighting: подсветка синтаксиса. zsh-autosuggestions: автодополнение. Переключение шелла на zsh: chsh -s /usr/bin/zsh, обратно на bash: chsh -s /usr/bin/bash.
Настройка # Мой конфиг .zshrc, необходимо сохранить в домашнюю директорию ~/.zshrc, если файл существует замените, .zshrc.
Так как oh-my-zsh установлен через yay, то строка ZSH=/usr/share/oh-my-zsh/ идет от корня, это касается и плагинов.
Тема оформления строки приветствия задается в данной строке ZSH_THEME=&quot;af-magic&quot;, сами темы можно выбрать тут.
Плагинов из набора oh-my-zsh полно, но я их не использую. wiki/Plugins.
plugins=(\r)\rИспользую только то, что установил дополнительно, путем экспорта в файл. Полный путь до .zsh файла. В зависимости от способа установки путь может отличаться, в данном случае такой.
source /usr/share/zsh/plugins/fast-syntax-highlighting/fast-syntax-highlighting.plugin.zsh\rsource /usr/share/zsh/plugins/zsh-autosuggestions/zsh-autosuggestions.zsh\rТут задаем дерикторию кэша и условие проверки.
ZSH_CACHE_DIR=$HOME/.cache/oh-my-zsh\r[[ ! -d $ZSH_CACHE_DIR ]] &amp;&amp; mkdir $ZSH_CACHE_DIR\rЭкспорт путей со скриптами и бинарниками.
export PATH=$HOME/.bin:$HOME/.bin/popup:$HOME/.local/bin:/usr/local/bin:$PATH\rЭкспорт различных переменных.
export TERM=&quot;rxvt-unicode&quot;\rexport EDITOR=&quot;$(if [[ -n $DISPLAY ]]; then echo 'subl3'; else echo 'nano'; fi)&quot;\rexport BROWSER=&quot;chromium&quot;\rexport SSH_KEY_PATH=&quot;~/.ssh/dsa_id&quot;\rexport XDG_CONFIG_HOME=&quot;$HOME/.config&quot;\rУсловие проверки и загрузки файла. Алиасы можно и не выносить в отдельный файл, но так удобнее.
[[ -f ~/.alias_zsh ]] &amp;&amp; . ~/.alias_zsh\rДанный блок не обязателен, отвечает за fzf поиск.
[[ -e &quot;/usr/share/fzf/fzf-extras.zsh&quot; ]] &amp;&amp; source /usr/share/fzf/fzf-extras.zsh\rexport FZF_DEFAULT_COMMAND=&quot;fd --type file --color=always --follow --hidden --exclude .git&quot;\rexport FZF_CTRL_T_COMMAND=&quot;$FZF_DEFAULT_COMMAND&quot;\r# export FZF_DEFAULT_OPTS=&quot;--ansi&quot;\rexport FZF_DEFAULT_OPTS=&quot;--height 50% --layout=reverse --border --preview 'file {}' --preview-window down:1&quot;\rexport FZF_COMPLETION_TRIGGER=&quot;~~&quot;\rВ момент набора и появления автодополнения можно перемещаться по словам Ctrl+стрелка вправо, а просто стрелка вправо прыжок в конец подсвеченной строки. Вот собственно и все.
Читайте также # Настройка терминала Urxvt — установка, шрифты, цвета, плагины `}),e.add({id:19,href:"/posts/urxvt-config/",title:"Arch Urxvt, установка и настройка",description:"Установка и настройка терминала Urxvt в Arch Linux: шрифты, цвета, копирование/вставка, perl-плагины и горячие клавиши.",content:`Очень быстрый и функциональный терминал, но немного пугает в настройке.
Установка # Я всегда устанавливаю patched версию с аура, некоторые зависимости и шрифт Hack Nerd с набором иконок, Мой конфиг github.
yay -S rxvt-unicode-patched urxvt-perls nerd-fonts-hack\rНастройка urxvt # Файл ~/.Xresources, ! Это комментарий. Строки с Xft не относятся к urxvt.
URxvt.font: xft:Hack Nerd Font Mono:size=9\rURxvt.geometry: 84x22\rURxvt.internalBorder: 15\rURxvt.letterSpace: 0\rURxvt.antialias: true\rURxvt.iconFile: /usr/share/icons/Papirus/48x48/apps/urxvt.svg\rшрифт. геометрия. отступ. меж буквенное расстояние. файл иконки, как раз за это и отвечает rxvt-unicode-patched. Строки ниже, отвечают за копирование/вставка по Ctrl-Shift-c/v.
URxvt.iso14755: false\rURxvt.iso14755_52: false\rURxvt.clipboard.autocopy: true\rURxvt.keysym.Shift-Control-V: eval:paste_clipboard\rURxvt.keysym.Shift-Control-C: eval:selection_to_clipboard\rОстальное, перл плагины для открытия ссылок по клику и некоторые кастомные клавиши.
URxvt.perl-ext-common: default,clipboard,url-select,keyboard-select,matcher\rURxvt.url-launcher: /usr/bin/xdg-open\rURxvt.url-select.underline: true\rURxvt.matcher.button: 1\rURxvt.keysym.Control-Up: 033[1;5A\rURxvt.keysym.Control-Down: 033[1;5B\rURxvt.keysym.Control-Left: 033[1;5D\rURxvt.keysym.Control-Right: 033[1;5C\rconfig-reload Необходим для смены цвета на лету, не обязательно, поэтому опустил.
Настройка цветов # Отключение непрозрачности.
URxvt.transparent:false\rURxvt.depth: 32\rВсе схемы я храню в ~/.colors, а подключаю их инклюдом. # В данном случае не комментарий, github.com/creio/dots/tree/master/.colors.
#include &quot;.colors/ln&quot;\rПросто цвета, что тут еще сказать. Все что начинается с rofi не обязательно, это цвета лаунчера rofi. Прозрачность фона я обычно задаю через [90] в процентах.
*.background: [90]#111113\rРекомендую создать симлинк на rxvt.
sudo ln -s /usr/bin/urxvt /usr/bin/rxvt\rКомбинации клавиш.
ctrl+стрелка вправо/влево: перемешение по словам. ctrl+a/e: перемешение в начало/конец строки. ctrl+q: очистить строку. ctrl+w: удалить слово. ctrl+l: очистить экран. ctrl+c: остановить процесс, сбросить набор. Есть вопросы, пиши в комментах. После изменения файла ~/.Xresources необходимо считывать конфиг и перезапускать терминал.
xrdb -merge ~/.Xresources\rЧитайте также # Настройка Zsh — oh-my-zsh, плагины, конфигурация ~/.zshrc `}),search.addEventListener("input",t,!0);function t(){const o=5;var t,s=this.value,i=e.search(s,{limit:o,enrich:!0});const n=new Map;for(const e of i.flatMap(e=>e.result)){if(n.has(e.doc.href))continue;n.set(e.doc.href,e.doc)}if(suggestions.innerHTML="",suggestions.classList.remove("d-none"),n.size===0&&s){const e=document.createElement("div");e.innerHTML=`No results for "<strong>${s}</strong>"`,e.classList.add("suggestion__no-results"),suggestions.appendChild(e);return}for(const[c,r]of n){const s=document.createElement("div");suggestions.appendChild(s);const e=document.createElement("a");e.href=c,s.appendChild(e);const i=document.createElement("span");i.textContent=r.title,i.classList.add("suggestion__title"),e.appendChild(i);const a=document.createElement("span");if(t=r.description||"",t.length>120&&(t=t.substring(0,120)+"…"),a.textContent=t,a.classList.add("suggestion__description"),e.appendChild(a),suggestions.appendChild(s),suggestions.childElementCount==o)break}}})();var suggestions,search,Tawk_API=Tawk_API||{},Tawk_LoadStart=new Date;(function(){var e=document.createElement("script"),t=document.getElementsByTagName("script")[0];e.async=!0,e.src="https://embed.tawk.to/647f954f94cf5d49dc5c312a/1h295ug1i",e.charset="UTF-8",e.setAttribute("crossorigin","*"),t.parentNode.insertBefore(e,t)})()